To create a simple chat server and client using WebSockets in Golang, we will use the "github.com/gorilla/websocket" package. First, you need to install this package by running:

```bash
go get github.com/gorilla/websocket
```

Now let's create the server and client code.

**Server (server.go):**

```go
package main

import (
	"fmt"
	"log"
	"net/http"

	"github.com/gorilla/websocket"
)

var clients = make(map[*websocket.Conn]bool)
var broadcast = make(chan Message)

var upgrader = websocket.Upgrader{
	CheckOrigin: func(r *http.Request) bool {
		return true
	},
}

type Message struct {
	Message string `json:"message"`
}

func main() {
	http.HandleFunc("/ws", handleConnections)

	go handleMessages()

	log.Println("Listening on :8080...")
	err := http.ListenAndServe(":8080", nil)
	if err != nil {
		log.Fatal("ListenAndServe: ", err)
	}
}

func handleConnections(w http.ResponseWriter, r *http.Request) {
	ws, err := upgrader.Upgrade(w, r, nil)
	if err != nil {
		log.Fatal(err)
	}
	defer ws.Close()

	clients[ws] = true

	for {
		var msg Message
		err := ws.ReadJSON(&msg)
		if err != nil {
			delete(clients, ws)
			break
		}

		broadcast <- msg
	}
}

func handleMessages() {
	for {
		msg := <-broadcast
		for client := range clients {
			err := client.WriteJSON(msg)
			if err != nil {
				log.Printf("Error: %v", err)
				client.Close()
				delete(clients, client)
			}
		}
	}
}
```

**Client (client.html):**

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>WebSocket Chat</title>
    <style>
        #messageInput {
            width: 300px;
        }
    </style>
</head>
<body>
    <h1>WebSocket Chat</h1>
    <ul id="messages"></ul>
    <input type="text" id="messageInput" placeholder="Type a message...">
    <button onclick="sendMessage()">Send</button>

    <script>
        const socket = new WebSocket("ws://localhost:8080/ws");

        socket.onmessage = (event) => {
            let messagesList = document.getElementById("messages");
            let messageItem = document.createElement("li");
            messageItem.textContent = event.data;
            messagesList.appendChild(messageItem);
        };

        function sendMessage() {
            let messageInput = document.getElementById("messageInput");
            let message = messageInput.value.trim();
            if (message !== "") {
                socket.send(JSON.stringify({ "message": message }));
                messageInput.value = "";
            }
        }
    </script>
</body>
</html>
```

To run the server, execute `go run server.go` in your terminal. Then open the `client.html` file in multiple browser windows to test the chat functionality.

