Below is a simple example of a Go program that interacts with a MariaDB database. It uses the `go-sql-driver/mysql` package to connect to the database.

```go
package main

import (
	"database/sql"
	"fmt"
	"log"

	_ "github.com/go-sql-driver/mysql"
)

type User struct {
	ID       int    `json:"id"`
	Name     string `json:"name"`
	Email    string `json:"email"`
	Password string `json:"password"`
}

var db *sql.DB

func main() {
	var err error
	db, err = sql.Open("mysql", "user:password@tcp(127.0.0.1:3306)/dbname")
	if err != nil {
		log.Fatal(err)
	}
	defer db.Close()

	err = db.Ping()
	if err != nil {
		log.Fatal(err)
	}

	fmt.Println("Successfully connected!")

	// Perform CRUD operations here...
}

func createUser(user User) (int64, error) {
	result, err := db.Exec(`INSERT INTO users(name, email, password) VALUES (?, ?, ?)`, user.Name, user.Email, user.Password)
	if err != nil {
		return 0, err
	}

	id, err := result.LastInsertId()
	if err != nil {
		return 0, err
	}

	return id, nil
}

func getUser(id int) (*User, error) {
	user := &User{}
	row := db.QueryRow(`SELECT id, name, email, password FROM users WHERE id = ?`, id)
	err := row.Scan(&user.ID, &user.Name, &user.Email, &user.Password)
	if err != nil {
		return nil, err
	}

	return user, nil
}

func updateUser(user User) error {
	_, err := db.Exec(`UPDATE users SET name = ?, email = ?, password = ? WHERE id = ?`, user.Name, user.Email, user.Password, user.ID)
	return err
}

func deleteUser(id int) error {
	_, err := db.Exec(`DELETE FROM users WHERE id = ?`, id)
	return err
}
```

Please replace `"user:password@tcp(127.0.0.1:3306)/dbname"` with your actual database connection details. The functions `createUser`, `getUser`, `updateUser`, and `deleteUser` perform the basic CRUD operations on the 'users' table.

Remember to handle passwords securely in a real-world application - don't store them as plain text like in this example.

To develop a web scraper using Puppeteer, you'll need to have Node.js installed on your system. You can download it from the official website: https://nodejs.org/

Once you have Node.js installed, follow these steps:

1. Create a new folder for your project and navigate to it in your terminal or command prompt.

2. Run `npm init` to create a package.json file. Follow the prompts to set up your project.

3. Install Puppeteer by running `npm install puppeteer`.

4. Create a new JavaScript file (e.g., `scraper.js`) and open it in your favorite code editor.

5. Add the following code to import the required modules and set up basic configurations:

```javascript
const fs = require('fs');
const puppeteer = require('puppeteer');

(async () => {
  // Your scraping code will go here.
})();
```

6. Inside the async function, add the following code to launch a browser instance, navigate to the e-commerce website's search results page, and wait for the content to load:

```javascript
const browser = await puppeteer.launch({ headless: false });
const page = await browser.newPage();
await page.goto('https://example.com/search?q=product'); // Replace this URL with the actual search results page URL.
await page.waitForSelector('.product-listing'); // Replace '.product-listing' with the appropriate selector for the product list container.
```

7. Next, extract the product details (name, price, and image URL) using the `$eval()` method and CSS selectors specific to the target website:

```javascript
const products = await page.$$eval('.product-item', items => { // Replace '.product-item' with the appropriate selector for individual product items.
  return items.map(item => {
    const name = item.querySelector('.product-name').innerText; // Replace '.product-name' with the appropriate selector for the product name.
    const price = item.querySelector('.product-price').innerText; // Replace '.product-price' with the appropriate selector for the product price.
    const imageUrl = item.querySelector('.product-image img').src; // Replace '.product-image img' with the appropriate selector for the product image.

    return { name, price, imageUrl };
  });
