```

8. Save the extracted data in a JSON file:

```javascript
fs.writeFileSync('products.json', JSON.stringify(products, null, 2));
```

9. Close the browser instance and log a success message:

```javascript
await browser.close();
console.log('Product details have been saved to products.json');
```

10. Your complete `scraper.js` file should look like this:

```javascript
const fs = require('fs');
const puppeteer = require('puppeteer');

(async () => {
  const browser = await puppeteer.launch({ headless: false });
  const page = await browser.newPage();
  await page.goto('https://example.com/search?q=product');
  await page.waitForSelector('.product-listing');

  const products = await page.$$eval('.product-item', items => {
    return items.map(item => {
      const name = item.querySelector('.product-name').innerText;
      const price = item.querySelector('.product-price').innerText;
      const imageUrl = item.querySelector('.product-image img').src;

      return { name, price, imageUrl };
    });
  });

  fs.writeFileSync('products.json', JSON.stringify(products, null, 2));

  await browser.close();
  console.log('Product details have been saved to products.json');
})();
```

11. Run your scraper by executing `node scraper.js` in your terminal or command prompt. The extracted product details will be saved in a `products.json` file within your project folder.

Note that you'll need to replace the example URL and CSS selectors with the actual values for the e-commerce website you're targeting.

package main

import (
	"fmt"
	"os"
	"strconv"
)

func main() {
	if len(os.Args) != 4 {
		fmt.Println("Usage: calc <number1> <operator> <number2>")
		os.Exit(1)
	}

	num1, err := strconv.ParseFloat(os.Args[1], 64)
	if err != nil {
		fmt.Printf("Invalid number: %s\n", os.Args[1])
		os.Exit(1)
	}

	operator := os.Args[2]

	num2, err := strconv.ParseFloat(os.Args[3], 64)
	if err != nil {
		fmt.Printf("Invalid number: %s\n", os.Args[3])
		os.Exit(1)
	}

	var result float64

	switch operator {
	case "+":
		result = num1 + num2
	case "-":
		result = num1 - num2
	case "*":
		result = num1 * num2
	case "/":
		if num2 == 0 {
			fmt.Println("Error: Division by zero")
			os.Exit(1)
		}
		result = num1 / num2
	default:
		fmt.Printf("Invalid operator: %s\n", operator)
		os.Exit(1)
	}

	fmt.Printf("%.2f %s %.2f = %.2f\n", num1, operator, num2, result)
}

To create a RESTful API server using GoLang that interacts with PostgreSQL, we need to install the following packages:

1. Gorilla Mux for routing: `go get -u github.com/gorilla/mux`
2. Go's pq driver to interact with PostgreSQL: `go get github.com/lib/pq`

Below is an example of how you can implement it.

```go
package main

import (
	"database/sql"
	"encoding/json"
	"fmt"
	"log"
	"net/http"

	"github.com/gorilla/mux"
	_ "github.com/lib/pq"
)

type User struct {
	ID   string `json:"id"`
	Name string `json:"name"`
}

var db *sql.DB

func main() {
	var err error
	db, err = sql.Open("postgres", "user=YOUR_USER password=YOUR_PASSWORD dbname=YOUR_DB sslmode=disable")
	if err != nil {
		log.Fatal(err)
	}
	router := mux.NewRouter()
	router.HandleFunc("/users", getUsers).Methods("GET")
	router.HandleFunc("/users/{id}", getUser).Methods("GET")
	router.HandleFunc("/users", createUser).Methods("POST")
	router.HandleFunc("/users/{id}", updateUser).Methods("PUT")
	router.HandleFunc("/users/{id}", deleteUser).Methods("DELETE")

	log.Fatal(http.ListenAndServe(":8000", router))
}

func getUsers(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")
	var users []User
	result, err := db.Query("SELECT id, name from users")
	if err != nil {
		panic(err.Error())
	}
	defer result.Close()
	for result.Next() {
		var user User
		err := result.Scan(&user.ID, &user.Name)
		if err != nil {
			panic(err.Error())
		}
		users = append(users, user)
	}
	json.NewEncoder(w).Encode(users)
}

func getUser(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")
	params := mux.Vars(r)
	result, err := db.Query("SELECT id, name FROM users WHERE id = $1", params["id"])
	if err != nil {
		panic(err.Error())
	}
	defer result.Close()
	var user User
	for result.Next() {
		err := result.Scan(&user.ID, &user.Name)
		if err != nil {
			panic(err.Error())
		}
	}
	json.NewEncoder(w).Encode(user)
}

func createUser(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")
	var user User
	_ = json.NewDecoder(r.Body).Decode(&user)
	statement, err := db.Prepare("INSERT INTO users(name) VALUES($1)")
	if err != nil {
		panic(err.Error())
	}
	statement.Exec(user.Name)
	json.NewEncoder(w).Encode(user)
}

func updateUser(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")
	params := mux.Vars(r)
	var user User
	_ = json.NewDecoder(r.Body).Decode(&user)
	statement, err := db.Prepare("UPDATE users SET name=$1 WHERE id=$2")
	if err != nil {
		panic(err.Error())
	}
	statement.Exec(user.Name, params["id"])
	json.NewEncoder(w).Encode(user)
}

func deleteUser(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")
	params := mux.Vars(r)
	statement, err := db.Prepare("DELETE FROM users WHERE id = $1")
	if err != nil {
		panic(err.Error())
	}
	statement.Exec(params["id"])
	fmt.Fprintf(w, "User with ID = %s was deleted", params["id"])
}
```

Please replace `"user=YOUR_USER password=YOUR_PASSWORD dbname=YOUR_DB sslmode=disable"` with your actual database credentials.

