package main

import (
	"fmt"
	"io/ioutil"
	"log"
	"net/http"
	"os"
	"path/filepath"
	"strings"
	"sync"
	"time"

	"github.com/gorilla/mux"
	"golang.org/x/time/rate"
)

const (
	staticDir    = "./static" // directory to serve static files from
	maxUploadSize = 10 << 20   // 10 MB
)

var (
	rateLimiter *rate.Limiter
	mutex       sync.Mutex
)

func init() {
	rateLimiter = rate.NewLimiter(1, 5) // allow 1 request per second with a burst of 5 requests
}

func main() {
	router := mux.NewRouter()

	router.HandleFunc("/upload", uploadHandler).Methods("POST")
	router.HandleFunc("/delete/{filename}", deleteHandler).Methods("DELETE")
	router.PathPrefix("/").Handler(http.FileServer(http.Dir(staticDir)))

	http.Handle("/", router)
	log.Fatal(http.ListenAndServe(":8080", nil))
}

func rateLimit(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		mutex.Lock()
		defer mutex.Unlock()

		if !rateLimiter.Allow() {
			http.Error(w, "Too many requests. Please try again later.", http.StatusTooManyRequests)
			return
		}
		next.ServeHTTP(w, r)
	})
}

func uploadHandler(w http.ResponseWriter, r *http.Request) {
	err := r.ParseMultipartForm(maxUploadSize)
	if err != nil {
		http.Error(w, "Error parsing form data", http.StatusBadRequest)
		return
	}

	file, header, err := r.FormFile("file")
	if err != nil {
		http.Error(w, "Error retrieving file from form data", http.StatusBadRequest)
		return
	}
	defer file.Close()

	fileBytes, err := ioutil.ReadAll(file)
	if err != nil {
		http.Error(w, "Error reading file", http.StatusInternalServerError)
		return
	}

	filename := header.Filename
	newPath := filepath.Join(staticDir, filename)

	err = ioutil.WriteFile(newPath, fileBytes, 0644)
	if err != nil {
		http.Error(w, "Error saving file", http.StatusInternalServerError)
		return
	}

	fmt.Fprintf(w, "File uploaded successfully: %s\n", filename)
}

func deleteHandler(w http.ResponseWriter, r *http.Request) {
	vars := mux.Vars(r)
	filename := vars["filename"]

	path := filepath.Join(staticDir, filename)

	if !strings.HasPrefix(path, staticDir) {
		http.Error(w, "Invalid file path", http.StatusBadRequest)
		return
	}

	err := os.Remove(path)
	if err != nil {
		http.Error(w, "Error deleting file", http.StatusInternalServerError)
		return
	}

	fmt.Fprintf(w, "File deleted successfully: %s\n", filename)
}

To create a Golang RESTful API that manages a simple inventory system, follow these steps:

1. Install required packages
First, install the necessary packages for creating the API and connecting to PostgreSQL:

```bash
go get -u github.com/gin-gonic/gin
go get -u github.com/jinzhu/gorm
go get -u github.com/jinzhu/gorm/dialects/postgres
```

2. Create main.go file
Create a `main.go` file with the following content:

```go
package main

import (
	"github.com/gin-gonic/gin"
	"github.com/jinzhu/gorm"
	_ "github.com/jinzhu/gorm/dialects/postgres"
)

var db *gorm.DB
var err error

type Item struct {
	ID       uint   `json:"id"`
	Name     string `json:"name" binding:"required"`
	Quantity int    `json:"quantity" binding:"required"`
	Price    float64 `json:"price" binding:"required"`
}

func main() {
	// Connect to PostgreSQL database
	db, err = gorm.Open("postgres", "host=localhost user=your_user dbname=inventory_db sslmode=disable password=your_password")
	if err != nil {
		panic("failed to connect database")
	}
	defer db.Close()

	// Migrate the schema
	db.AutoMigrate(&Item{})

	r := gin.Default()

	// Routes
	r.GET("/items", GetItems)
	r.GET("/items/:id", GetItem)
	r.POST("/items", AddItem)
	r.PUT("/items/:id", UpdateItem)
	r.DELETE("/items/:id", DeleteItem)

	// Run the server
	r.Run(":8080")
}

func GetItems(c *gin.Context) {
	var items []Item
	if err := db.Find(&items).Error; err != nil {
		c.AbortWithStatus(404)
	} else {
		c.JSON(200, items)
	}
}

func GetItem(c *gin.Context) {
	id := c.Params.ByName("id")
	var item Item
	if err := db.Where("id = ?", id).First(&item).Error; err != nil {
		c.AbortWithStatus(404)
	} else {
		c.JSON(200, item)
	}
}

func AddItem(c *gin.Context) {
	var item Item
	if err := c.ShouldBindJSON(&item); err == nil {
		db.Create(&item)
		c.JSON(201, item)
	} else {
		c.JSON(400, gin.H{"error": err.Error()})
	}
}

func UpdateItem(c *gin.Context) {
	var item Item
	id := c.Params.ByName("id")

	if err := db.Where("id = ?", id).First(&item).Error; err != nil {
		c.AbortWithStatus(404)
		return
	}

	if err := c.ShouldBindJSON(&item); err == nil {
		db.Save(&item)
		c.JSON(200, item)
	} else {
		c.JSON(400, gin.H{"error": err.Error()})
	}
}

func DeleteItem(c *gin.Context) {
	id := c.Params.ByName("id")
	var item Item

	if err := db.Where("id = ?", id).Delete(&item).Error; err != nil {
		c.AbortWithStatus(404)
	} else {
		c.JSON(204, gin.H{"id #" + id: "deleted"})
	}
}
```

Replace `your_user`, `your_password`, and `inventory_db` with your PostgreSQL username, password, and database name.

3. Run the API server
Run the following command to start the API server:

```bash
go run main.go
```

The server will start on port 8080, and you can use a tool like Postman or curl to test the CRUD operations.

Remember that this is just a simple example of how to create a RESTful API in Golang with PostgreSQL. In a production environment, you should consider adding more error handling, validation, logging, and security features.

