func main() {
	if len(os.Args) < 4 {
		log.Fatalf("Usage: %s <index> <keyword> <max_results>", os.Args[0])
	}

	index := os.Args[1]
	keyword := os.Args[2]
	maxResults := os.Args[3]

	esClient, err := elasticsearch.NewDefaultClient()
	if err != nil {
		log.Fatalf("Error creating Elasticsearch client: %s", err)
	}

	query := map[string]interface{}{
		"query": map[string]interface{}{
			"match": map[string]interface{}{
				"_all": keyword,
			},
		},
		"size": maxResults,
	}

	var buf bytes.Buffer
	err = json.NewEncoder(&buf).Encode(query)
	if err != nil {
		log.Fatalf("Error encoding query: %s", err)
	}

	res, err := esClient.Search(
		esClient.Search.WithContext(context.Background()),
		esClient.Search.WithIndex(index),
		esClient.Search.WithBody(&buf),
		esClient.Search.WithTrackTotalHits(true),
		esClient.Search.WithPretty(),
	)
	if err != nil {
		log.Fatalf("Error getting response: %s", err)
	}
	defer res.Body.Close()

	if res.IsError() {
		var e map[string]interface{}
		err := json.NewDecoder(res.Body).Decode(&e)
		if err != nil {
			log.Fatalf("Error parsing the response body: %s", err)
		} else {
			log.Printf("Error: [%d] %s: %s",
				res.StatusCode,
				e["error"].(map[string]interface{})["type"],
				e["error"].(map[string]interface{})["reason"],
			)
		}
		os.Exit(1)
	}

	var r map[string]interface{}
	err = json.NewDecoder(res.Body).Decode(&r)
	if err != nil {
		log.Fatalf("Error parsing the response body: %s", err)
	}

	hits := int(r["hits"].(map[string]interface{})["total"].(map[string]interface{})["value"].(float64))
	fmt.Printf("Found a total of %d hits\n", hits)

	for _, hit := range r["hits"].(map[string]interface{})["hits"].([]interface{}) {
		source := hit.(map[string]interface{})["_source"]
		jsonStr, _ := json.MarshalIndent(source, "", "  ")
		fmt.Println(string(jsonStr))
	}
}

