	Name        string `json:"name"`
	Description string `json:"description"`
	Price       float64 `json:"price"`
}

// initDB initializes the connection to the PostgreSQL database and returns a pointer to the gorm.DB object
func initDB() *gorm.DB {
	db, err := gorm.Open("postgres", "host=localhost user=your_user dbname=your_db_name sslmode=disable password=your_password")
	if err != nil {
		fmt.Println(err)
		panic("failed to connect to the database")
	}

	db.AutoMigrate(&Product{})
	return db
}

// createProduct handles creating a new product in the database
func createProduct(c *gin.Context, db *gorm.DB) {
	var product Product
	c.BindJSON(&product)

	db.Create(&product)
	c.JSON(200, product)
}

// getProducts retrieves all products from the database
func getProducts(c *gin.Context, db *gorm.DB) {
	var products []Product
	db.Find(&products)
	c.JSON(200, products)
}

// getProduct retrieves a single product by ID from the database
func getProduct(c *gin.Context, db *gorm.DB) {
	id := c.Params.ByName("id")
	var product Product
	if err := db.Where("id = ?", id).First(&product).Error; err != nil {
		c.AbortWithStatus(404)
		return
	}
	c.JSON(200, product)
}

// updateProduct updates an existing product in the database
func updateProduct(c *gin.Context, db *gorm.DB) {
	var product Product
	id := c.Params.ByName("id")

	if err := db.Where("id = ?", id).First(&product).Error; err != nil {
		c.AbortWithStatus(404)
		return
	}

	c.BindJSON(&product)
	db.Save(&product)
	c.JSON(200, product)
}

// deleteProduct deletes a product by ID from the database
func deleteProduct(c *gin.Context, db *gorm.DB) {
	id := c.Params.ByName("id")
	var product Product

	if err := db.Where("id = ?", id).Delete(&product).Error; err != nil {
		c.AbortWithStatus(404)
		return
	}
	c.JSON(200, gin.H{"id #" + id: "deleted"})
}

