package main

import (
	"bufio"
	"fmt"
	"os"
	"sort"
	"strings"
	"sync"
)

type WordCount struct {
	word  string
	count int
}

func main() {
	if len(os.Args) < 2 {
		fmt.Println("Please provide a text file as an argument.")
		return
	}

	file, err := os.Open(os.Args[1])
	if err != nil {
		fmt.Printf("Error opening file: %v\n", err)
		return
	}
	defer file.Close()

	scanner := bufio.NewScanner(file)
	scanner.Split(bufio.ScanWords)

	wordChan := make(chan string)
	go func() {
		for scanner.Scan() {
			word := strings.ToLower(scanner.Text())
			word = strings.Trim(word, ".,!?:;\"'()[]{}<>")
			wordChan <- word
		}
		close(wordChan)
	}()

	var wg sync.WaitGroup
	wordCounts := make(map[string]int)
	mux := &sync.Mutex{}

	for i := 0; i < 10; i++ {
		wg.Add(1)
		go func() {
			for word := range wordChan {
				mux.Lock()
				wordCounts[word]++
				mux.Unlock()
			}
			wg.Done()
		}()
	}

	wg.Wait()

	topWordCounts := getTopNWords(wordCounts, 10)
	for _, wc := range topWordCounts {
		fmt.Printf("%s: %d\n", wc.word, wc.count)
	}
}

func getTopNWords(wordCounts map[string]int, n int) []WordCount {
	wordList := make([]WordCount, 0, len(wordCounts))
	for word, count := range wordCounts {
		wordList = append(wordList, WordCount{word, count})
	}

	sort.Slice(wordList, func(i, j int) bool {
		return wordList[i].count > wordList[j].count
	})

	if len(wordList) < n {
		return wordList
	}
	return wordList[:n]
}

