)

var (
	port     string
	dir      string
	username string
	password string
)

func init() {
	flag.StringVar(&port, "port", "8080", "Port to listen on")
	flag.StringVar(&dir, "dir", ".", "Directory to serve files from")
	flag.StringVar(&username, "user", "", "Username for basic authentication")
	flag.StringVar(&password, "pass", "", "Password for basic authentication")
}

// BasicAuth is a middleware function that checks for valid basic authentication credentials
func BasicAuth(handler http.HandlerFunc) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		user, pass, ok := r.BasicAuth()
		if !ok || user != username || pass != password {
			w.Header().Set("WWW-Authenticate", `Basic realm="Restricted"`)
			http.Error(w, "Unauthorized.", http.StatusUnauthorized)
			return
		}
		handler.ServeHTTP(w, r)
	}
}

func main() {
	flag.Parse()

	router := mux.NewRouter()

	fileServer := http.FileServer(http.Dir(dir))
	if username != "" && password != "" {
		log.Println("Using basic authentication")
		router.PathPrefix("/").Handler(BasicAuth(http.StripPrefix("/", fileServer).ServeHTTP))
	} else {
		router.PathPrefix("/").Handler(http.StripPrefix("/", fileServer))
	}

	addr := fmt.Sprintf(":%s", port)
	log.Printf("Listening on %s, serving files from %s\n", addr, dir)
	err := http.ListenAndServe(addr, router)
	if err != nil {
		log.Fatal("ListenAndServe: ", err)
	}
}

package main

import (
	"fmt"
	"io/ioutil"
	"net/http"
	"net/url"
	"os"
	"strings"

	"golang.org/x/net/html"
)

func main() {
	if len(os.Args) != 2 {
		fmt.Println("Usage: go run main.go <URL>")
		os.Exit(1)
	}

	inputURL := os.Args[1]

	resp, err := http.Get(inputURL)
	if err != nil {
		fmt.Printf("Error fetching URL: %v\n", err)
		os.Exit(1)
	}
	defer resp.Body.Close()

	pageContent, err := ioutil.ReadAll(resp.Body)
	if err != nil {
		fmt.Printf("Error reading response body: %v\n", err)
		os.Exit(1)
	}

	links := extractLinks(string(pageContent), inputURL)

	err = writeLinksToFile(links, "output.txt")
	if err != nil {
		fmt.Printf("Error writing links to file: %v\n", err)
		os.Exit(1)
	}

	fmt.Println("Links successfully extracted and saved to output.txt.")
}

func extractLinks(content string, baseURL string) []string {
	var links []string
	tokenizer := html.NewTokenizer(strings.NewReader(content))

	for {
		tt := tokenizer.Next()
		switch tt {
		case html.ErrorToken:
			return links
		case html.StartTagToken, html.SelfClosingTagToken:
			token := tokenizer.Token()
			if token.Data == "a" {
				for _, attr := range token.Attr {
					if attr.Key == "href" {
						link := resolveLink(attr.Val, baseURL)
						links = append(links, link)
						break
					}
				}
			}
		}
	}
}

func resolveLink(link string, baseURL string) string {
	if strings.HasPrefix(link, "http://") || strings.HasPrefix(link, "https://") {
		return link
	}

	base, err := url.Parse(baseURL)
	if err != nil {
		return ""
	}

	resolvedLink := base.ResolveReference(&url.URL{Path: link})
	return resolvedLink.String()
}

func writeLinksToFile(links []string, filename string) error {
	file, err := os.Create(filename)
	if err != nil {
		return err
	}
	defer file.Close()

	for _, link := range links {
		_, err = file.WriteString(link + "\n")
		if err != nil {
			return err
		}
	}

	return nil
}

