	"net/http"

	"github.com/gorilla/mux"
	_ "github.com/lib/pq"
)

type Book struct {
	ID     string `json:"id"`
	Title  string `json:"title"`
	Author string `json:"author"`
}

var db *sql.DB

func main() {
	router := mux.NewRouter()

	var err error
	db, err = sql.Open("postgres", "user=YOUR_USERNAME password=YOUR_PASSWORD dbname=bookstore sslmode=disable")
	if err != nil {
		log.Fatal(err)
	}

	router.HandleFunc("/books", getBooks).Methods("GET")
	router.HandleFunc("/books/{id}", getBook).Methods("GET")
	router.HandleFunc("/books", createBook).Methods("POST")
	router.HandleFunc("/books/{id}", updateBook).Methods("PUT")
	router.HandleFunc("/books/{id}", deleteBook).Methods("DELETE")

	log.Fatal(http.ListenAndServe(":8000", router))
}

func getBooks(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")

	var books []Book

	result, err := db.Query("SELECT id, title, author from books")
	if err != nil {
		panic(err.Error())
	}

	defer result.Close()
	for result.Next() {
		var book Book
		err := result.Scan(&book.ID, &book.Title, &book.Author)
		if err != nil {
			panic(err.Error())
		}
		books = append(books, book)
	}

	json.NewEncoder(w).Encode(books)
}

func getBook(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")
	params := mux.Vars(r)

	result, err := db.Query("SELECT id, title, author FROM books WHERE id = $1", params["id"])
	if err != nil {
		panic(err.Error())
	}

	defer result.Close()

	var book Book

	for result.Next() {
		err := result.Scan(&book.ID, &book.Title, &book.Author)
		if err != nil {
			panic(err.Error())
		}
	}

	json.NewEncoder(w).Encode(book)
}

func createBook(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")

	var book Book
	_ = json.NewDecoder(r.Body).Decode(&book)

	insertStmt := `INSERT INTO books(id, title, author) VALUES($1, $2, $3)`
	_, err := db.Exec(insertStmt, book.ID, book.Title, book.Author)
	if err != nil {
		panic(err.Error())
	}

	json.NewEncoder(w).Encode(book)
}

func updateBook(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")
	params := mux.Vars(r)

	var book Book
	_ = json.NewDecoder(r.Body).Decode(&book)

	updateStmt := `UPDATE books SET title=$1, author=$2 WHERE id=$3`
	_, err := db.Exec(updateStmt, book.Title, book.Author, params["id"])
	if err != nil {
		panic(err.Error())
	}

	json.NewEncoder(w).Encode(book)
}

func deleteBook(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")
	params := mux.Vars(r)

	deleteStmt := `DELETE FROM books WHERE id=$1`
	_, err := db.Exec(deleteStmt, params["id"])
	if err != nil {
		panic(err.Error())
	}

	fmt.Fprintf(w, "Book with ID = %s was deleted", params["id"])
}

