// areAnagrams checks if two strings are anagrams of each other
func areAnagrams(s1, s2 string) bool {
	if len(s1) != len(s2) {
		return false
	}

	charCount := make(map[rune]int)
	for _, char := range s1 {
		charCount[char]++
	}

	for _, char := range s2 {
		charCount[char]--
		if charCount[char] < 0 {
			return false
		}
	}

	return true
}

func main() {
	s1 := "listen"
	s2 := "silent"

	fmt.Printf("Are '%s' and '%s' anagrams? %v\n", s1, s2, areAnagrams(s1, s2))
}

