```javascript
const express = require('express');
const bodyParser = require('body-parser');

const app = express();
app.use(bodyParser.json());

// In-memory storage for books
let books = [];

// GET all books
app.get('/books', (req, res) => {
  const { author, title } = req.query;

  let filteredBooks = books;

  if (author) {
    filteredBooks = filteredBooks.filter(book => book.author === author);
  }

  if (title) {
    filteredBooks = filteredBooks.filter(book => book.title.includes(title));
  }

  res.send(filteredBooks);
});

// POST a new book
app.post('/books', (req, res) => {
  const { title, author, publicationYear, isbn } = req.body;
  const newBook = { title, author, publicationYear, isbn };
  books.push(newBook);
  res.status(201).send(newBook);
});

// GET a single book by ISBN
app.get('/books/:isbn', (req, res) => {
  const { isbn } = req.params;
  const book = books.find(b => b.isbn === isbn);

  if (!book) {
    return res.status(404).send({ message: 'Book not found' });
  }

  res.send(book);
});

// PUT update a book by ISBN
app.put('/books/:isbn', (req, res) => {
  const { isbn } = req.params;
  const index = books.findIndex(b => b.isbn === isbn);

  if (index === -1) {
    return res.status(404).send({ message: 'Book not found' });
  }

  const updatedBook = { ...books[index], ...req.body };
  books[index] = updatedBook;
  res.send(updatedBook);
});

// DELETE a book by ISBN
app.delete('/books/:isbn', (req, res) => {
  const { isbn } = req.params;
  const index = books.findIndex(b => b.isbn === isbn);

  if (index === -1) {
    return res.status(404).send({ message: 'Book not found' });
  }

  books.splice(index, 1);
  res.status(204).send();
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => console.log(`Server running on port ${PORT}`));
```

