package main

import (
	"encoding/json"
	"flag"
	"fmt"
	"io/ioutil"
	"net/http"
	"strings"
	"time"

	"github.com/gorilla/mux"
	"golang.org/x/time/rate"
)

type RateLimiter struct {
	rate  int
	burst int
}

var elasticsearchHost string
var elasticsearchPort int
var apiKey string
var rateLimiters map[string]*rate.Limiter

func init() {
	flag.StringVar(&elasticsearchHost, "host", "localhost", "Elasticsearch host")
	flag.IntVar(&elasticsearchPort, "port", 9200, "Elasticsearch port")
	flag.StringVar(&apiKey, "apikey", "", "API key for authentication")

	rateLimiters = make(map[string]*rate.Limiter)
}

func getRateLimiter(ip string) *rate.Limiter {
	if limiter, exists := rateLimiters[ip]; exists {
		return limiter
	}
	newLimiter := rate.NewLimiter(rate.Every(time.Minute), 100)
	rateLimiters[ip] = newLimiter
	return newLimiter
}

func proxyHandler(w http.ResponseWriter, r *http.Request) {
	ip := strings.Split(r.RemoteAddr, ":")[0]
	limiter := getRateLimiter(ip)

	if !limiter.Allow() {
		http.Error(w, "Too many requests", http.StatusTooManyRequests)
		return
	}

	url := fmt.Sprintf("http://%s:%d%s", elasticsearchHost, elasticsearchPort, r.URL.Path)
	req, err := http.NewRequest(r.Method, url, r.Body)
	if err != nil {
		http.Error(w, "Error creating request", http.StatusInternalServerError)
		return
	}

	for name, values := range r.Header {
		for _, value := range values {
			req.Header.Add(name, value)
		}
	}

	req.Header.Set("Authorization", fmt.Sprintf("ApiKey %s", apiKey))

	client := &http.Client{}
	resp, err := client.Do(req)
	if err != nil {
		http.Error(w, "Error forwarding request", http.StatusInternalServerError)
		return
	}
	defer resp.Body.Close()

	body, err := ioutil.ReadAll(resp.Body)
	if err != nil {
		http.Error(w, "Error reading response body", http.StatusInternalServerError)
		return
	}

	var jsonResponse map[string]interface{}
	err = json.Unmarshal(body, &jsonResponse)
	if err != nil {
		http.Error(w, "Error unmarshalling JSON", http.StatusInternalServerError)
		return
	}

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(jsonResponse)
}

func main() {
	flag.Parse()
	router := mux.NewRouter()
	router.PathPrefix("/").HandlerFunc(proxyHandler)

	fmt.Printf("Starting proxy server on :8080\n")
	http.ListenAndServe(":8080", router)
}

