// Fetch the data from a URL and print it.
func fetch(url string, wg *sync.WaitGroup) {
	defer wg.Done()

	resp, err := http.Get(url)
	if err != nil {
		fmt.Println(err)
		return
	}
	defer resp.Body.Close()

	body, err := ioutil.ReadAll(resp.Body)
	if err != nil {
		fmt.Println(err)
		return
	}

	fmt.Printf("URL: %s \nData: %s\n", url, body)
}

func main() {
	var wg sync.WaitGroup

	// Loop over command line arguments (ignoring the first one which is the program name).
	for _, url := range os.Args[1:] {
		wg.Add(1)

		// Start a goroutine to fetch the data from each URL concurrently.
		go fetch(url, &wg)
	}

	// Wait for all fetches to complete.
	wg.Wait()
}

