func serveStaticFiles(w http.ResponseWriter, r *http.Request) {
	staticDir := "./static" // Specify your static files directory here

	filePath := filepath.Join(staticDir, r.URL.Path)
	info, err := os.Stat(filePath)
	if err != nil || info.IsDir() {
		http.NotFound(w, r)
		return
	}

	http.ServeFile(w, r, filePath)
}

func fetchURLContent(w http.ResponseWriter, r *http.Request) {
	url := r.URL.Query().Get("url")
	if url == "" {
		http.Error(w, "Missing 'url' parameter", http.StatusBadRequest)
		return
	}

	resp, err := http.Get(url)
	if err != nil {
		http.Error(w, fmt.Sprintf("Error fetching URL: %v", err), http.StatusInternalServerError)
		return
	}
	defer resp.Body.Close()

	node, err := html.Parse(resp.Body)
	if err != nil {
		http.Error(w, fmt.Sprintf("Error parsing HTML: %v", err), http.StatusInternalServerError)
		return
	}

	removeScriptsAndStyles(node)

	html.Render(w, node)
}

func removeScriptsAndStyles(n *html.Node) {
	if n.Type == html.ElementNode && (n.Data == "script" || n.Data == "style" || n.Data == "img") {
		n.Parent.RemoveChild(n)
		return
	}

	for c := n.FirstChild; c != nil; c = c.NextSibling {
		removeScriptsAndStyles(c)
	}
}

