// longestIncreasingSubsequence finds the longest increasing subsequence in an array of integers using dynamic programming.
func longestIncreasingSubsequence(arr []int) []int {
	n := len(arr)
	if n == 0 {
		return arr
	}

	dp := make([]int, n)
	for i := range dp {
		dp[i] = 1
	}
	parents := make([]int, n)
	for i := range parents {
		parents[i] = -1
	}

	longestEnd := 0
	longestLength := 1

	for i := 1; i < n; i++ {
		for j := 0; j < i; j++ {
			if arr[i] > arr[j] && dp[i] < dp[j]+1 {
				dp[i] = dp[j] + 1
				parents[i] = j
			}
		}
		if dp[i] > longestLength {
			longestLength = dp[i]
			longestEnd = i
		}
	}

	result := make([]int, longestLength)
	k := longestEnd
	for i := longestLength - 1; i >= 0; i-- {
		result[i] = arr[k]
		k = parents[k]
	}

	return result
}

func main() {
	arr := []int{10, 22, 9, 33, 21, 50, 41, 60, 80}
	fmt.Println("Array:", arr)
	fmt.Println("Longest Increasing Subsequence:", longestIncreasingSubsequence(arr))
}

