Here is a simple example of how you can interact with PostgreSQL database in GoLang. In this example, we will be using the `pq` package to connect and perform CRUD operations on a table named "users".

```go
package main

import (
	"database/sql"
	"fmt"
	"log"

	_ "github.com/lib/pq"
)

const (
	host     = "localhost"
	port     = 5432
	user     = "postgres"
	password = "your-password"
	dbname   = "test_db"
)

type User struct {
	ID    int
	Name  string
	Email string
}

func main() {
	psqlInfo := fmt.Sprintf("host=%s port=%d user=%s "+
		"password=%s dbname=%s sslmode=disable",
		host, port, user, password, dbname)

	db, err := sql.Open("postgres", psqlInfo)
	if err != nil {
		panic(err)
	}
	defer db.Close()

	err = db.Ping()
	if err != nil {
		panic(err)
	}

	fmt.Println("Successfully connected!")

	// Create
	createUser(db, "John Doe", "johndoe@example.com")

	// Read
	users := getUsers(db)
	for _, user := range users {
		fmt.Printf("ID: %v, Name: %v, Email: %v\n", user.ID, user.Name, user.Email)
	}

	// Update
	updateUser(db, 1, "Jane Doe", "janedoe@example.com")

	// Delete
	deleteUser(db, 1)
}

func createUser(db *sql.DB, name string, email string) {
	sqlStatement := `
	INSERT INTO users (name, email)
	VALUES ($1, $2)`
	_, err := db.Exec(sqlStatement, name, email)
	if err != nil {
		log.Fatalf("Unable to execute the query. %v", err)
	}
	fmt.Println("Inserted a single record")
}

func getUsers(db *sql.DB) []User {
