package main

import (
	"bytes"
	"encoding/json"
	"fmt"
	"io/ioutil"
	"net/http"

	"github.com/aws/aws-sdk-go/aws"
	"github.com/aws/aws-sdk-go/aws/session"
	"github.com/aws/aws-sdk-go/service/s3"
	"github.com/gorilla/mux"
)

type ErrorResponse struct {
	Message string `json:"message"`
}

func createBucketHandler(s3Client *s3.S3) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		bucketName := r.URL.Query().Get("bucket")

		input := &s3.CreateBucketInput{
			Bucket: aws.String(bucketName),
		}

		_, err := s3Client.CreateBucket(input)
		if err != nil {
			w.WriteHeader(http.StatusInternalServerError)
			json.NewEncoder(w).Encode(ErrorResponse{Message: err.Error()})
			return
		}

		w.WriteHeader(http.StatusOK)
		fmt.Fprintf(w, "Bucket %s created successfully", bucketName)
	}
}

func uploadFileHandler(s3Client *s3.S3) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		bucketName := r.URL.Query().Get("bucket")
		fileName := r.URL.Query().Get("file")

		file, _, err := r.FormFile("file")
		if err != nil {
			w.WriteHeader(http.StatusBadRequest)
			json.NewEncoder(w).Encode(ErrorResponse{Message: err.Error()})
			return
		}
		defer file.Close()

		buffer, err := ioutil.ReadAll(file)
		if err != nil {
			w.WriteHeader(http.StatusInternalServerError)
			json.NewEncoder(w).Encode(ErrorResponse{Message: err.Error()})
			return
		}

		input := &s3.PutObjectInput{
			Bucket: aws.String(bucketName),
			Key:    aws.String(fileName),
			Body:   bytes.NewReader(buffer),
		}

		_, err = s3Client.PutObject(input)
		if err != nil {
			w.WriteHeader(http.StatusInternalServerError)
			json.NewEncoder(w).Encode(ErrorResponse{Message: err.Error()})
			return
		}

		w.WriteHeader(http.StatusOK)
		fmt.Fprintf(w, "File %s uploaded to bucket %s", fileName, bucketName)
	}
}

func downloadFileHandler(s3Client *s3.S3) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		bucketName := r.URL.Query().Get("bucket")
		fileName := r.URL.Query().Get("file")

		input := &s3.GetObjectInput{
			Bucket: aws.String(bucketName),
			Key:    aws.String(fileName),
		}

		result, err := s3Client.GetObject(input)
		if err != nil {
			w.WriteHeader(http.StatusInternalServerError)
			json.NewEncoder(w).Encode(ErrorResponse{Message: err.Error()})
			return
		}
		defer result.Body.Close()

		buffer, err := ioutil.ReadAll(result.Body)
		if err != nil {
			w.WriteHeader(http.StatusInternalServerError)
			json.NewEncoder(w).Encode(ErrorResponse{Message: err.Error()})
			return
		}

		w.Header().Set("Content-Disposition", "attachment; filename="+fileName)
		w.Write(buffer)
	}
}

func deleteFileHandler(s3Client *s3.S3) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		bucketName := r.URL.Query().Get("bucket")
		fileName := r.URL.Query().Get("file")

		input := &s3.DeleteObjectInput{
			Bucket: aws.String(bucketName),
			Key:    aws.String(fileName),
		}

		_, err := s3Client.DeleteObject(input)
		if err != nil {
			w.WriteHeader(http.StatusInternalServerError)
			json.NewEncoder(w).Encode(ErrorResponse{Message: err.Error()})
			return
		}

		w.WriteHeader(http.StatusOK)
		fmt.Fprintf(w, "File %s deleted from bucket %s", fileName, bucketName)
	}
}

func main() {
	sess := session.Must(session.NewSession(&aws.Config{
		Region: aws.String("us-west-2"),
	}))

	s3Client := s3.New(sess)

	router := mux.NewRouter()
	router.HandleFunc("/createBucket", createBucketHandler(s3Client)).Methods("POST")
	router.HandleFunc("/uploadFile", uploadFileHandler(s3Client)).Methods("POST")
	router.HandleFunc("/downloadFile", downloadFileHandler(s3Client)).Methods("GET")
	router.HandleFunc("/deleteFile", deleteFileHandler(s3Client)).Methods("DELETE")

	http.ListenAndServe(":8080", router)
}

Here's a simple Golang program that implements a REST API for managing tasks:

```go
package main

import (
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"strconv"

	"github.com/gorilla/mux"
)

type Task struct {
	ID       int    `json:"id"`
	Title    string `json:"title"`
	Status   string `json:"status"`
}

var tasks []Task

func getTasks(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")
	status := r.URL.Query().Get("status")

	var filteredTasks []Task
	for _, task := range tasks {
		if status == "" || task.Status == status {
			filteredTasks = append(filteredTasks, task)
		}
	}

	json.NewEncoder(w).Encode(filteredTasks)
}

func createTask(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")
	var newTask Task
	json.NewDecoder(r.Body).Decode(&newTask)
	newTask.ID = len(tasks) + 1
	tasks = append(tasks, newTask)
	json.NewEncoder(w).Encode(newTask)
}

func updateTask(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")
	params := mux.Vars(r)
	id, _ := strconv.Atoi(params["id"])

	var updatedTask Task
	json.NewDecoder(r.Body).Decode(&updatedTask)

	for i, task := range tasks {
		if task.ID == id {
			tasks[i].Title = updatedTask.Title
			tasks[i].Status = updatedTask.Status
			json.NewEncoder(w).Encode(tasks[i])
			return
		}
	}

	http.Error(w, "Task not found", http.StatusNotFound)
}

func deleteTask(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")
	params := mux.Vars(r)
	id, _ := strconv.Atoi(params["id"])

	for i, task := range tasks {
		if task.ID == id {
			tasks = append(tasks[:i], tasks[i+1:]...)
			break
		}
	}

	json.NewEncoder(w).Encode(tasks)
}

func main() {
	router := mux.NewRouter()

	tasks = append(tasks, Task{ID: 1, Title: "Task One", Status: "pending"})
	tasks = append(tasks, Task{ID: 2, Title: "Task Two", Status: "completed"})

	router.HandleFunc("/tasks", getTasks).Methods("GET")
	router.HandleFunc("/tasks", createTask).Methods("POST")
	router.HandleFunc("/tasks/{id}", updateTask).Methods("PUT")
	router.HandleFunc("/tasks/{id}", deleteTask).Methods("DELETE")

	fmt.Println("Server running on port 8000")
	log.Fatal(http.ListenAndServe(":8000", router))
}
```

