		os.Exit(1)
	}

	printTable(records)
}

func printTable(records [][]string) {
	columnWidths := getColumnWidths(records)

	for _, row := range records {
		for i, cell := range row {
			fmt.Printf("%-*s ", columnWidths[i], cell)
		}
		fmt.Println()
	}
}

func getColumnWidths(records [][]string) []int {
	widths := make([]int, len(records[0]))

	for _, row := range records {
		for i, cell := range row {
			cellLength := len(strings.TrimSpace(cell))
			if widths[i] < cellLength {
				widths[i] = cellLength
			}
		}
	}

	return widths
}

