type FibResponse struct {
	N        int    `json:"n"`
	FibValue int64  `json:"fib_value"`
	Error    string `json:"error,omitempty"`
}

var fibMemo = make(map[int]int64)
var mutex sync.Mutex

func main() {
	http.HandleFunc("/api/fib/", fibHandler)
	http.Handle("/", http.FileServer(http.Dir("./static")))

	port := "8080"
	if len(os.Args) > 1 {
		port = os.Args[1]
	}
	fmt.Printf("Listening on :%s...\n", port)
	err := http.ListenAndServe(":"+port, nil)
	if err != nil {
		panic(err)
	}
}

func fibHandler(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")

	nStr := r.URL.Path[len("/api/fib/"):]
	n, err := strconv.Atoi(nStr)
	if err != nil || n <= 0 {
		response := FibResponse{
			N:     -1,
			Error: fmt.Sprintf("Invalid input '%s'. Please provide a positive integer.", nStr),
		}
		json.NewEncoder(w).Encode(response)
		return
	}

	fibValue := fibonacci(n)
	response := FibResponse{
		N:        n,
		FibValue: fibValue,
	}
	json.NewEncoder(w).Encode(response)
}

func fibonacci(n int) int64 {
	if n <= 2 {
		return 1
	}

	mutex.Lock()
	value, exists := fibMemo[n]
	mutex.Unlock()

	if exists {
		return value
	}

	fibNMinus1 := fibonacci(n - 1)
	fibNMinus2 := fibonacci(n - 2)

	mutex.Lock()
	fibMemo[n] = fibNMinus1 + fibNMinus2
	mutex.Unlock()

	return fibMemo[n]
}

