package main

import (
	"compress/gzip"
	"flag"
	"fmt"
	"io"
	"os"
	"path/filepath"
	"strings"
)

func main() {
	var input string
	var output string
	var level int
	var decompress bool

	flag.StringVar(&input, "i", "", "Input file or directory")
	flag.StringVar(&output, "o", "", "Output file or directory")
	flag.IntVar(&level, "l", gzip.DefaultCompression, "Compression level (0-9)")
	flag.BoolVar(&decompress, "d", false, "Decompress mode")

	flag.Parse()

	if input == "" || output == "" {
		fmt.Println("Please specify both input and output paths.")
		os.Exit(1)
	}

	err := filepath.Walk(input, func(path string, info os.FileInfo, err error) error {
		if err != nil {
			return err
		}

		if !info.IsDir() {
			outPath := strings.Replace(path, input, output, 1)

			if decompress {
				err = decompressFile(path, outPath)
			} else {
				err = compressFile(path, outPath, level)
			}

			if err != nil {
				return err
			}
		}

		return nil
	})

	if err != nil {
		fmt.Printf("Error: %v\n", err)
		os.Exit(1)
	}
}

func compressFile(src, dest string, level int) error {
	srcFile, err := os.Open(src)
	if err != nil {
		return err
	}
	defer srcFile.Close()

	err = os.MkdirAll(filepath.Dir(dest), 0755)
	if err != nil {
		return err
	}

	destFile, err := os.Create(dest + ".gz")
	if err != nil {
		return err
	}
	defer destFile.Close()

	gw, err := gzip.NewWriterLevel(destFile, level)
	if err != nil {
		return err
	}
	defer gw.Close()

	_, err = io.Copy(gw, srcFile)
	return err
}

func decompressFile(src, dest string) error {
	srcFile, err := os.Open(src)
	if err != nil {
		return err
	}
	defer srcFile.Close()

	gr, err := gzip.NewReader(srcFile)
	if err != nil {
		return err
	}
	defer gr.Close()

	err = os.MkdirAll(filepath.Dir(dest), 0755)
	if err != nil {
		return err
	}

	destFile, err := os.Create(strings.TrimSuffix(dest, ".gz"))
	if err != nil {
		return err
	}
	defer destFile.Close()

	_, err = io.Copy(destFile, gr)
	return err
}

Here's a Golang program that monitors a specified directory for changes and sends notifications to a specified email address using an SMTP server when changes are detected. Make sure to replace the placeholders with your own information.

```go
package main

import (
	"fmt"
	"log"
	"net/smtp"
	"os"
	"path/filepath"
	"time"

	"github.com/fsnotify/fsnotify"
)

const (
	smtpServer   = "smtp.example.com:587" // Replace with your SMTP server and port
	senderEmail  = "you@example.com"       // Replace with your sender email address
	password     = "your-password"         // Replace with your sender email password
	receiverEmail = "recipient@example.com" // Replace with your recipient email address
)

func sendEmail(subject, body string) {
	auth := smtp.PlainAuth("", senderEmail, password, smtpServer)
	msg := []byte("To: " + receiverEmail + "\r\n" +
		"Subject: " + subject + "\r\n" +
		"\r\n" +
		body + "\r\n")

	err := smtp.SendMail(smtpServer, auth, senderEmail, []string{receiverEmail}, msg)
	if err != nil {
		log.Printf("Failed to send email: %v", err)
	} else {
		log.Println("Email sent successfully")
	}
}

func monitorDirectory(dir string) {
	watcher, err := fsnotify.NewWatcher()
	if err != nil {
		log.Fatal(err)
	}
	defer watcher.Close()

	done := make(chan bool)
	go func() {
		for {
			select {
			case event, ok := <-watcher.Events:
				if !ok {
					return
				}
				log.Println("event:", event)
				if event.Op&fsnotify.Write == fsnotify.Write {
					sendEmail("File Modified", fmt.Sprintf("Modified file: %s", event.Name))
				} else if event.Op&fsnotify.Create == fsnotify.Create {
					sendEmail("File Created", fmt.Sprintf("Created file: %s", event.Name))
				} else if event.Op&fsnotify.Remove == fsnotify.Remove {
					sendEmail("File Deleted", fmt.Sprintf("Deleted file: %s", event.Name))
				}
			case err, ok := <-watcher.Errors:
				if !ok {
					return
				}
				log.Println("error:", err)
			}
		}
	}()

	err = watcher.Add(dir)
	if err != nil {
		log.Fatal(err)
	}
	<-done
}

func main() {
	dirToMonitor := "path/to/your/directory" // Replace with the directory you want to monitor

	absPath, err := filepath.Abs(dirToMonitor)
	if err != nil {
		log.Fatalf("Failed to get absolute path of directory: %v", err)
	}

	fmt.Printf("Monitoring directory: %s\n", absPath)
	monitorDirectory(absPath)
}
```

