package main

import (
	"flag"
	"fmt"
	"math/rand"
	"time"
)

const (
	lowercaseLetters = "abcdefghijklmnopqrstuvwxyz"
	uppercaseLetters = "ABCDEFGHIJKLMNOPQRSTUVWXYZ"
	digits           = "0123456789"
	specialChars     = "!@#$%^&*()-_=+{}[]|;:,.<>?/~`"
	allChars         = lowercaseLetters + uppercaseLetters + digits + specialChars
)

func main() {
	length := flag.Int("length", 8, "Password length")
	flag.Parse()

	if *length < 4 {
		fmt.Println("Error: Password length must be at least 4.")
		return
	}

	rand.Seed(time.Now().UnixNano())
	password := generateRandomPassword(*length)
	fmt.Printf("Generated password: %s\n", password)
}

func generateRandomPassword(length int) string {
	password := make([]byte, length)

	// Ensure there is at least one character from each required set.
	password[0] = lowercaseLetters[rand.Intn(len(lowercaseLetters))]
	password[1] = uppercaseLetters[rand.Intn(len(uppercaseLetters))]
	password[2] = digits[rand.Intn(len(digits))]
	password[3] = specialChars[rand.Intn(len(specialChars))]

	// Fill the rest of the password with random characters.
	for i := 4; i < length; i++ {
		password[i] = allChars[rand.Intn(len(allChars))]
	}

	// Shuffle the password to mix up the required characters.
	for i := range password {
		j := rand.Intn(i + 1)
		password[i], password[j] = password[j], password[i]
	}

	return string(password)
}

