	"github.com/Azure/go-autorest/autorest/azure/auth"
	ui "github.com/gizak/termui/v3"
	"github.com/gizak/termui/v3/widgets"
)

func main() {
	err := ui.Init()
	if err != nil {
		log.Fatalf("failed to initialize termui: %v", err)
	}
	defer ui.Close()

	resourceGroup := os.Getenv("AZURE_RESOURCE_GROUP")
	resourceURI := fmt.Sprintf("/subscriptions/%s/resourceGroups/%s/providers/Microsoft.Compute/virtualMachines/myVM", os.Getenv("AZURE_SUBSCRIPTION_ID"), resourceGroup)

	metricsClient, err := getMetricsClient()
	if err != nil {
		log.Fatal(err)
	}

	cpuGauge := widgets.NewGauge()
	memGauge := widgets.NewGauge()
	netSparkline := widgets.NewSparkline()

	grid := ui.NewGrid()
	termWidth, termHeight := ui.TerminalDimensions()
	grid.SetRect(0, 0, termWidth, termHeight)
	grid.Set(
		ui.NewRow(1.0/3,
			ui.NewCol(1.0/3, cpuGauge),
			ui.NewCol(1.0/3, memGauge),
			ui.NewCol(1.0/3, netSparkline),
		),
	)

	ui.Render(grid)

	ticker := time.NewTicker(time.Minute).C
	for {
		select {
		case <-ticker:
			cpuUsage, memUsage, netThroughput, err := getMetrics(metricsClient, resourceURI)
			if err != nil {
				log.Println(err)
				continue
			}

			cpuGauge.Percent = int(cpuUsage)
			memGauge.Percent = int(memUsage)
			netSparkline.Data = append(netSparkline.Data[1:], netThroughput)

			ui.Render(grid)
		}
	}
}

func getMetricsClient() (*insights.MetricsClient, error) {
	authorizer, err := auth.NewAuthorizerFromEnvironment()
	if err != nil {
		return nil, fmt.Errorf("failed to create authorizer: %v", err)
	}

	client := insights.NewMetricsClient(os.Getenv("AZURE_SUBSCRIPTION_ID"))
	client.Authorizer = authorizer

	return &client, nil
}

func getMetrics(client *insights.MetricsClient, resourceURI string) (float64, float64, float64, error) {
	ctx, cancel := context.WithTimeout(context.Background(), 30*time.Second)
	defer cancel()

	metricNames := []string{"Percentage CPU", "Memory\\Working Set", "Network In Total"}
	result, err := client.List(ctx, resourceURI, "PT1M", &metricNames, "", "", "value", "")
	if err != nil {
		return 0, 0, 0, fmt.Errorf("failed to retrieve metrics: %v", err)
	}

	var cpuUsage, memUsage, netThroughput float64
	for _, metric := range *result.Value {
		if len(*metric.Timeseries) == 0 || len((*metric.Timeseries)[0].Data) == 0 {
			continue
		}

		data := (*metric.Timeseries)[0].Data
		value := *data[len(data)-1].Average

		switch *metric.Name.Value {
		case "Percentage CPU":
			cpuUsage = value
		case "Memory\\Working Set":
			memUsage = value / (1024 * 1024)
		case "Network In Total":
			netThroughput = value
		}
	}

	return cpuUsage, memUsage, netThroughput, nil
}

package main

import (
	"fmt"
)

type Node struct {
	data int
	next *Node
}

type LinkedList struct {
	head *Node
	size int
}

// AddAtBeginning adds a new node with the given value at the beginning of the list.
func (list *LinkedList) AddAtBeginning(value int) {
	newNode := &Node{data: value}
	if list.head == nil {
		list.head = newNode
	} else {
		newNode.next = list.head
		list.head = newNode
	}
	list.size++
}

// AddAtEnd adds a new node with the given value at the end of the list.
func (list *LinkedList) AddAtEnd(value int) {
	newNode := &Node{data: value}
	if list.head == nil {
		list.head = newNode
	} else {
		current := list.head
		for current.next != nil {
			current = current.next
		}
		current.next = newNode
	}
	list.size++
}

// AddAtPosition adds a new node with the given value at the specified position in the list.
func (list *LinkedList) AddAtPosition(position, value int) {
	if position < 0 || position > list.size {
		fmt.Println("Invalid position")
		return
	}

	if position == 0 {
		list.AddAtBeginning(value)
		return
	}

	newNode := &Node{data: value}
	current := list.head
	index := 1
	for index < position {
		current = current.next
		index++
	}
	newNode.next = current.next
	current.next = newNode
	list.size++
}

// RemoveByValue removes the first node with the given value from the list.
func (list *LinkedList) RemoveByValue(value int) {
	if list.head == nil {
		return
	}

	if list.head.data == value {
		list.head = list.head.next
		list.size--
		return
	}

	current := list.head
	for current.next != nil && current.next.data != value {
		current = current.next
	}

	if current.next != nil {
		current.next = current.next.next
		list.size--
	}
}

// Display prints the contents of the list.
func (list *LinkedList) Display() {
	current := list.head
	for current != nil {
		fmt.Printf("%d -> ", current.data)
		current = current.next
	}
	fmt.Println("nil")
}

func main() {
	list := &LinkedList{}
	list.AddAtBeginning(1)
	list.AddAtEnd(2)
	list.AddAtEnd(3)
	list.Display()

	list.AddAtPosition(0, 0)
	list.AddAtPosition(4, 4)
	list.Display()

	list.RemoveByValue(0)
	list.RemoveByValue(4)
	list.Display()
}

