// extractLinks fetches all links from the given URL
func extractLinks(url string) ([]string, error) {
	var links []string

	resp, err := http.Get(url)
	if err != nil {
		return links, err
	}
	defer resp.Body.Close()

	doc, err := goquery.NewDocumentFromReader(resp.Body)
	if err != nil {
		return links, err
	}

	doc.Find("a").Each(func(_ int, s *goquery.Selection) {
		href, exists := s.Attr("href")
		if exists {
			links = append(links, href)
		}
	})

	return links, nil
}

// filterLinks separates internal and external links based on the baseURL
func filterLinks(baseURL string, links []string) ([]string, []string) {
	var internalLinks, externalLinks []string

	u, err := url.Parse(baseURL)
	if err != nil {
		log.Fatal(err)
	}

	for _, link := range links {
		linkURL, err := url.Parse(link)
		if err != nil {
			continue
		}

		if linkURL.Host == "" || linkURL.Host == u.Host {
			internalLinks = append(internalLinks, link)
		} else {
			externalLinks = append(externalLinks, link)
		}
	}

	return internalLinks, externalLinks
}

// saveToFile writes data to a file with the specified filename
func saveToFile(filename string, data []string) error {
	file, err := os.Create(filename)
	if err != nil {
		return err
	}
	defer file.Close()

	for _, line := range data {
		file.WriteString(line + "\n")
	}

	return nil
}

func main() {
	targetURL := "https://example.com" // Replace with the URL you want to scrape

	links, err := extractLinks(targetURL)
	if err != nil {
		log.Fatal(err)
	}

	internalLinks, externalLinks := filterLinks(targetURL, links)

	err = saveToFile("internal_links.txt", internalLinks)
	if err != nil {
		log.Fatal(err)
	}

	fmt.Printf("Total Links: %d\n", len(links))
	fmt.Printf("Internal Links: %d\n", len(internalLinks))
	fmt.Printf("External Links: %d\n", len(externalLinks))
}

Below is a simple example of a Golang REST API server with three endpoints for creating, updating, and deleting users. This example uses the Gorilla Mux router package to handle routing and stores user data in-memory using a map.

```go
package main

import (
	"encoding/json"
	"fmt"
	"github.com/gorilla/mux"
	"log"
	"net/http"
	"strconv"
)

type User struct {
	ID       int    `json:"id"`
	Username string `json:"username"`
	Email    string `json:"email"`
	Password string `json:"password"`
}

var users = make(map[int]User)
var userIDCounter = 1

func createUser(w http.ResponseWriter, r *http.Request) {
	var newUser User
	err := json.NewDecoder(r.Body).Decode(&newUser)
	if err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}
	newUser.ID = userIDCounter
	users[userIDCounter] = newUser
	userIDCounter++
	json.NewEncoder(w).Encode(newUser)
}

func updateUser(w http.ResponseWriter, r *http.Request) {
	idStr := mux.Vars(r)["id"]
	id, err := strconv.Atoi(idStr)
	if err != nil {
		http.Error(w, "Invalid user ID", http.StatusBadRequest)
		return
	}

	var updatedUser User
	err = json.NewDecoder(r.Body).Decode(&updatedUser)
	if err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}

	if _, exists := users[id]; !exists {
		http.Error(w, "User not found", http.StatusNotFound)
		return
	}

	updatedUser.ID = id
	users[id] = updatedUser
	json.NewEncoder(w).Encode(updatedUser)
}

func deleteUser(w http.ResponseWriter, r *http.Request) {
	idStr := mux.Vars(r)["id"]
	id, err := strconv.Atoi(idStr)
	if err != nil {
		http.Error(w, "Invalid user ID", http.StatusBadRequest)
		return
	}

	if _, exists := users[id]; !exists {
		http.Error(w, "User not found", http.StatusNotFound)
		return
	}

	delete(users, id)
	fmt.Fprintf(w, "User %d deleted", id)
}

func main() {
	router := mux.NewRouter()
	router.HandleFunc("/users", createUser).Methods("POST")
	router.HandleFunc("/users/{id}", updateUser).Methods("PUT")
	router.HandleFunc("/users/{id}", deleteUser).Methods("DELETE")

	log.Fatal(http.ListenAndServe(":8080", router))
}
```

