package main

import (
	"bufio"
	"fmt"
	"io/ioutil"
	"net"
	"os"
	"strings"
)

func main() {
	listener, err := net.Listen("tcp", "localhost:8080")
	if err != nil {
		fmt.Println(err)
		return
	}
	defer listener.Close()

	for {
		conn, err := listener.Accept()
		if err != nil {
			fmt.Println(err)
			continue
		}

		go handleConnection(conn)
	}
}

func handleConnection(conn net.Conn) {
	defer conn.Close()

	reader := bufio.NewReader(conn)
	command, _ := reader.ReadString('\n')
	parts := strings.Split(strings.TrimSpace(command), " ")

	switch parts[0] {
	case "UPLOAD":
		handleUpload(parts[1:], reader, conn)
	case "DOWNLOAD":
		handleDownload(parts[1:], conn)
	case "LIST":
		handleList(conn)
	case "DELETE":
		handleDelete(parts[1:], conn)
	default:
		conn.Write([]byte("Invalid command\n"))
	}
}

func handleUpload(parts []string, reader *bufio.Reader, conn net.Conn) {
	if len(parts) < 1 {
		conn.Write([]byte("Filename required for upload\n"))
		return
	}

	file, err := os.Create(parts[0])
	if err != nil {
		conn.Write([]byte(fmt.Sprintf("Error creating file: %s\n", err)))
		return
	}
	defer file.Close()

	content, _ := reader.ReadString('\n')
	file.WriteString(content)

	conn.Write([]byte("File uploaded successfully\n"))
}

func handleDownload(parts []string, conn net.Conn) {
	if len(parts) < 1 {
		conn.Write([]byte("Filename required for download\n"))
		return
	}

	data, err := ioutil.ReadFile(parts[0])
	if err != nil {
		conn.Write([]byte(fmt.Sprintf("Error reading file: %s\n", err)))
		return
	}

	conn.Write(data)
}

func handleList(conn net.Conn) {
	files, err := ioutil.ReadDir(".")
	if err != nil {
		conn.Write([]byte(fmt.Sprintf("Error listing files: %s\n", err)))
		return
	}

	for _, file := range files {
		conn.Write([]byte(file.Name() + "\n"))
	}
}

func handleDelete(parts []string, conn net.Conn) {
	if len(parts) < 1 {
		conn.Write([]byte("Filename required for delete\n"))
		return
	}

	err := os.Remove(parts[0])
	if err != nil {
		conn.Write([]byte(fmt.Sprintf("Error deleting file: %s\n", err)))
		return
	}

	conn.Write([]byte("File deleted successfully\n"))
}

