import (
	"fmt"
	"log"
	"os"
	"strings"

	"github.com/cjhutto/golang-sentiment/sentiment"
	"github.com/dghubble/go-twitter/twitter"
	"github.com/dghubble/oauth1"
)

func main() {
	if len(os.Args) < 2 {
		log.Fatal("Please provide a keyword to search for.")
	}

	keyword := os.Args[1]

	config := oauth1.NewConfig("<consumer-key>", "<consumer-secret>")
	token := oauth1.NewToken("<access-token>", "<access-token-secret>")
	httpClient := config.Client(oauth1.NoContext, token)

	client := twitter.NewClient(httpClient)
	searchParams := &twitter.SearchTweetParams{
		Query:      keyword,
		ResultType: "recent",
		Count:      100,
		Lang:       "en",
	}

	tweets, _, err := client.Search.Tweets(searchParams)
	if err != nil {
		log.Fatal(err)
	}

	wordCounts := make(map[string]int)
	totalSentiment := 0.0
	analyzer := sentiment.NewAnalyzer()

	for _, tweet := range tweets.Statuses {
		score, _ := analyzer.Analyze(tweet.Text)
		totalSentiment += score.Score

		words := strings.Split(strings.ToLower(tweet.Text), " ")
		for _, word := range words {
			wordCounts[word]++
		}
	}

	fmt.Printf("Total tweets analyzed: %d\n", len(tweets.Statuses))
	fmt.Printf("Average sentiment score: %.2f\n", totalSentiment/float64(len(tweets.Statuses)))

	fmt.Println("Most common words:")
	for word, count := range wordCounts {
		if count > 1 {
			fmt.Printf("%s: %d\n", word, count)
		}
	}
}

