First, you need to install the Redis client library for Go. You can use `go-redis` package which is a popular choice.

```bash
go get -u github.com/go-redis/redis/v8
```

Now, let's create a simple Golang program that interacts with Redis:

```go
package main

import (
	"context"
	"fmt"
	"time"

	"github.com/go-redis/redis/v8"
)

var ctx = context.Background()

func main() {
	// Initialize Redis client
	rdb := redis.NewClient(&redis.Options{
		Addr:     "localhost:6379",
		Password: "", // no password set
		DB:       0,  // use default DB
	})

	// Set key-value pair with expiration time
	err := rdb.Set(ctx, "mykey", "myvalue", 10*time.Second).Err()
	if err != nil {
		panic(err)
	}

	// Get value by key
	val, err := rdb.Get(ctx, "mykey").Result()
	if err == redis.Nil {
		fmt.Println("mykey does not exist")
	} else if err != nil {
		panic(err)
	} else {
		fmt.Println("mykey:", val)
	}

	// Wait for the key to expire
	time.Sleep(11 * time.Second)

	// Try to get the expired key
	val2, err := rdb.Get(ctx, "mykey").Result()
	if err == redis.Nil {
		fmt.Println("mykey has expired")
	} else if err != nil {
		panic(err)
	} else {
		fmt.Println("mykey:", val2)
	}
}
```

This program connects to a local Redis server and sets a key-value pair with an expiration time of 10 seconds. It then retrieves the value by its key and prints it. After waiting for 11 seconds, it tries to get the value again but since the key has expired, it prints that the key has expired.

package main

import (
	"encoding/json"
	"log"
	"net/http"

	"github.com/gocql/gocql"
	"github.com/gorilla/mux"
)

// User struct (Model)
type User struct {
	ID       gocql.UUID `json:"id"`
	Name     string     `json:"name"`
	Email    string     `json:"email"`
	Password string     `json:"password"`
}

var session *gocql.Session // Cassandra session global variable

func init() {
	var err error

	// Connect to the cluster
	cluster := gocql.NewCluster("127.0.0.1")
	cluster.Keyspace = "test"
	session, err = cluster.CreateSession()
	if err != nil {
		panic(err)
	}
	log.Println("cassandra init done")
}

// Get all users from the DB and return them
func getUsers(w http.ResponseWriter, r *http.Request) {
	var userList []User
	m := map[string]interface{}{}

	query := "SELECT id, name, email, password FROM users"
	iterable := session.Query(query).Iter()
	for iterable.MapScan(m) {
		userList = append(userList, User{
			ID:       m["id"].(gocql.UUID),
			Name:     m["name"].(string),
			Email:    m["email"].(string),
			Password: m["password"].(string),
		})
		m = map[string]interface{}{}
	}
	json.NewEncoder(w).Encode(userList)
}

// Insert a new user into the database
func createUser(w http.ResponseWriter, r *http.Request) {
	var user User
	_ = json.NewDecoder(r.Body).Decode(&user)
	user.ID = gocql.TimeUUID()

	if err := session.Query(`INSERT INTO users (id, name, email, password) VALUES (?, ?, ?, ?)`,
		user.ID, user.Name, user.Email, user.Password).Exec(); err != nil {
		log.Fatal(err)
	}

	json.NewEncoder(w).Encode(user)
}

// Update an existing user in the database
func updateUser(w http.ResponseWriter, r *http.Request) {
	var user User
	params := mux.Vars(r)
	_ = json.NewDecoder(r.Body).Decode(&user)

	if err := session.Query(`UPDATE users SET name = ?, email = ?, password = ? WHERE id = ?`,
		user.Name, user.Email, user.Password, params["id"]).Exec(); err != nil {
		log.Fatal(err)
	}

	json.NewEncoder(w).Encode(user)
}

// Delete a user from the database
func deleteUser(w http.ResponseWriter, r *http.Request) {
	params := mux.Vars(r)

	if err := session.Query(`DELETE FROM users WHERE id = ?`, params["id"]).Exec(); err != nil {
		log.Fatal(err)
	}

	json.NewEncoder(w).Encode(params["id"])
}

func main() {
	router := mux.NewRouter()

	// Route handles & endpoints
	router.HandleFunc("/users", getUsers).Methods("GET")
	router.HandleFunc("/users", createUser).Methods("POST")
	router.HandleFunc("/users/{id}", updateUser).Methods("PUT")
	router.HandleFunc("/users/{id}", deleteUser).Methods("DELETE")

	// Start server
	log.Fatal(http.ListenAndServe(":8000", router))
}

To create a real-time chat server using Gorilla WebSocket library in Golang, follow the steps below:

1. Install the Gorilla WebSocket library by running the following command:
```bash
go get github.com/gorilla/websocket
```

2. Create a new file called `main.go` and add the following code to it:

```go
package main

import (
	"fmt"
	"log"
	"net/http"

	"github.com/gorilla/websocket"
)

var clients = make(map[*websocket.Conn]bool)
var broadcast = make(chan Message)

var upgrader = websocket.Upgrader{
	CheckOrigin: func(r *http.Request) bool {
		return true
	},
}

type Message struct {
	Username string `json:"username"`
	Message  string `json:"message"`
}

func main() {
	fs := http.FileServer(http.Dir("public"))
	http.Handle("/", fs)

	http.HandleFunc("/ws", handleConnections)

	go handleMessages()

	log.Println("Listening on :8080...")
	err := http.ListenAndServe(":8080", nil)
	if err != nil {
		log.Fatal("ListenAndServe: ", err)
	}
}

func handleConnections(w http.ResponseWriter, r *http.Request) {
	ws, err := upgrader.Upgrade(w, r, nil)
	if err != nil {
		log.Fatal(err)
	}
	defer ws.Close()

	clients[ws] = true

	for {
		var msg Message
		err := ws.ReadJSON(&msg)
		if err != nil {
			delete(clients, ws)
			break
		}

		broadcast <- msg
	}
}

func handleMessages() {
	for {
		msg := <-broadcast
		fmt.Printf("%s: %s\n", msg.Username, msg.Message)

		for client := range clients {
			err := client.WriteJSON(msg)
			if err != nil {
				log.Printf("Error: %v", err)
				client.Close()
				delete(clients, client)
			}
		}
	}
}
```

3. Create a new folder called `public` and inside it create an `index.html` file with the following content:

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Chat</title>
    <style>
        #message-box {
            width: 100%;
            height: 300px;
            overflow-y: scroll;
        }
    </style>
</head>
<body>
    <div id="message-box"></div>
    <input type="text" id="username" placeholder="Username">
    <input type="text" id="message" placeholder="Message">
    <button onclick="sendMessage()">Send</button>

    <script>
        const messageBox = document.getElementById('message-box');
        const usernameInput = document.getElementById('username');
        const messageInput = document.getElementById('message');

        const socket = new WebSocket('ws://localhost:8080/ws');

        socket.onmessage = function(event) {
            const data = JSON.parse(event.data);
            messageBox.innerHTML += `<p><strong>${data.username}:</strong> ${data.message}</p>`;
        };

        function sendMessage() {
            const msg = {
                username: usernameInput.value,
                message: messageInput.value
            };
            socket.send(JSON.stringify(msg));
            messageInput.value = '';
        }
    </script>
</body>
</html>
```

