)

type Document struct {
	ID      string `json:"id"`
	Title   string `json:"title"`
	Content string `json:"content"`
}

func main() {
	esURL := flag.String("url", "http://localhost:9200", "Elasticsearch URL")
	indexName := flag.String("index", "documents", "Index name")
	searchQuery := flag.String("query", "", "Search query")

	flag.Parse()

	client, err := elastic.NewClient(elastic.SetURL(*esURL))
	if err != nil {
		log.Fatal(err)
	}

	ctx := context.Background()

	// Create index
	createIndex, err := client.CreateIndex(*indexName).Do(ctx)
	if err != nil {
		log.Fatal(err)
	}
	fmt.Printf("Index %s created\n", createIndex.Index)

	// Insert sample documents
	sampleDocs := []Document{
		{ID: "1", Title: "First document", Content: "This is the first sample document."},
		{ID: "2", Title: "Second document", Content: "This is the second sample document."},
		{ID: "3", Title: "Third document", Content: "This is the third sample document."},
	}

	for _, doc := range sampleDocs {
		_, err = client.Index().
			Index(*indexName).
			Id(doc.ID).
			BodyJson(doc).
			Do(ctx)
		if err != nil {
			log.Fatal(err)
		}
		fmt.Printf("Inserted document with ID %s\n", doc.ID)
	}

	// Perform search
	if *searchQuery != "" {
		query := elastic.NewMatchQuery("content", *searchQuery)
		searchResult, err := client.Search().
			Index(*indexName).
			Query(query).
			Do(ctx)
		if err != nil {
			log.Fatal(err)
		}

		fmt.Printf("Found %d documents matching query '%s'\n", searchResult.TotalHits(), *searchQuery)

		for _, hit := range searchResult.Hits.Hits {
			var doc Document
			err := json.Unmarshal(hit.Source, &doc)
			if err != nil {
				log.Fatal(err)
			}
			fmt.Printf("Document ID: %s, Title: %s\n", doc.ID, doc.Title)
		}
	} else {
		fmt.Println("No search query provided")
	}
}
