Here's a simple Golang program that simulates a producer-consumer scenario using goroutines and channels. The producer generates random numbers, while the consumer calculates their average.

```go
package main

import (
	"fmt"
	"math/rand"
	"sync"
	"time"
)

const (
	numProducers = 5
	numConsumers = 2
	bufferSize   = 10
)

func main() {
	rand.Seed(time.Now().UnixNano())

	dataChannel := make(chan int, bufferSize)
	var wg sync.WaitGroup

	for i := 0; i < numProducers; i++ {
		wg.Add(1)
		go func(id int) {
			defer wg.Done()
			producer(dataChannel, id)
		}(i)
	}

	for i := 0; i < numConsumers; i++ {
		wg.Add(1)
		go func(id int) {
			defer wg.Done()
			consumer(dataChannel, id)
		}(i)
	}

	wg.Wait()
	close(dataChannel)
	fmt.Println("All producers and consumers have finished.")
}

func producer(data chan<- int, id int) {
	for i := 0; i < 10; i++ {
		num := rand.Intn(100)
		fmt.Printf("Producer %d generated number: %d\n", id, num)
		data <- num
		time.Sleep(time.Duration(rand.Intn(500)) * time.Millisecond)
	}
}

func consumer(data <-chan int, id int) {
	count := 0
	sum := 0
	for num := range data {
		fmt.Printf("Consumer %d received number: %d\n", id, num)
		sum += num
		count++
		if count == (numProducers * 10) / numConsumers {
			break
		}
	}
	average := float64(sum) / float64(count)
	fmt.Printf("Consumer %d calculated average: %.2f\n", id, average)
}
```

This program creates a fixed number of producers and consumers using goroutines. The producer generates random numbers and sends them to the data channel. The consumer reads from the data channel and calculates the average of the received numbers.

You can adjust the `numProducers`, `numConsumers`, and `bufferSize` constants to change the number of producers, consumers, and the size of the buffer for the data channel.

package cmd

import (
	"fmt"
	"io/ioutil"
	"os"
	"path/filepath"

	"github.com/spf13/cobra"
)

var syncFlag bool

func init() {
	rootCmd.AddCommand(compareCmd)
	compareCmd.Flags().BoolVarP(&syncFlag, "sync", "s", false, "Synchronize the content of the two directories")
}

var compareCmd = &cobra.Command{
	Use:   "compare [dir1] [dir2]",
	Short: "Compare and optionally synchronize the contents of two directories",
	Long:  `This command compares the contents of two directories recursively and reports any differences.`,
	Args:  cobra.ExactArgs(2),
	Run: func(cmd *cobra.Command, args []string) {
		dir1 := args[0]
		dir2 := args[1]

		err := compareDirectories(dir1, dir2, syncFlag)
		if err != nil {
			fmt.Println("Error:", err)
			os.Exit(1)
		}
	},
}

func compareDirectories(dir1, dir2 string, syncDirs bool) error {
	filepath.Walk(dir1, func(path string, info os.FileInfo, err error) error {
		if err != nil {
			return err
		}

		relPath, _ := filepath.Rel(dir1, path)
		pathInDir2 := filepath.Join(dir2, relPath)

		info2, err := os.Stat(pathInDir2)
		if os.IsNotExist(err) {
			fmt.Printf("Missing in %s: %s\n", dir2, relPath)
			if syncDirs {
				err = copyFileOrDirectory(path, pathInDir2)
				if err != nil {
					return err
				}
			}
		} else if info.IsDir() != info2.IsDir() {
			fmt.Printf("Type mismatch: %s\n", relPath)
		} else if !info.IsDir() && !info2.IsDir() {
			same, err := compareFiles(path, pathInDir2)
			if err != nil {
				return err
			}
			if !same {
				fmt.Printf("Modified: %s\n", relPath)
				if syncDirs {
					err = copyFileOrDirectory(path, pathInDir2)
					if err != nil {
						return err
					}
				}
			}
		}

		return nil
	})

	return nil
}

func compareFiles(file1, file2 string) (bool, error) {
	data1, err := ioutil.ReadFile(file1)
	if err != nil {
		return false, err
	}

	data2, err := ioutil.ReadFile(file2)
	if err != nil {
		return false, err
	}

	return string(data1) == string(data2), nil
}

func copyFileOrDirectory(src, dst string) error {
	srcInfo, err := os.Stat(src)
	if err != nil {
		return err
	}

	if srcInfo.IsDir() {
		return copyDirectory(src, dst)
	} else {
		return copyFile(src, dst)
	}
}

func copyFile(src, dst string) error {
	data, err := ioutil.ReadFile(src)
	if err != nil {
		return err
	}

	err = ioutil.WriteFile(dst, data, 0644)
	if err != nil {
		return err
	}

	return nil
}

func copyDirectory(src, dst string) error {
	err := os.MkdirAll(dst, 0755)
	if err != nil {
		return err
	}

	files, err := ioutil.ReadDir(src)
	if err != nil {
		return err
	}

	for _, file := range files {
		srcPath := filepath.Join(src, file.Name())
		dstPath := filepath.Join(dst, file.Name())

		err = copyFileOrDirectory(srcPath, dstPath)
		if err != nil {
			return err
		}
	}

	return nil
}

