	"github.com/pborman/uuid"
)

const (
	S3_BUCKET = "your-s3-bucket-name"
)

func main() {
	router := mux.NewRouter()
	router.HandleFunc("/upload", UploadImage).Methods("POST")
	router.HandleFunc("/images/{id}", GetImage).Methods("GET")

	http.ListenAndServe(":8080", router)
}

// UploadImage handles image uploading, resizing and storing in S3
func UploadImage(w http.ResponseWriter, r *http.Request) {
	file, _, err := r.FormFile("image")
	if err != nil {
		w.WriteHeader(http.StatusBadRequest)
		return
	}
	defer file.Close()

	img, _, err := image.Decode(file)
	if err != nil {
		w.WriteHeader(http.StatusBadRequest)
		return
	}

	resizedImg := resize.Resize(100, 0, img, resize.Lanczos3)

	buf := new(bytes.Buffer)
	err = jpeg.Encode(buf, resizedImg, nil)
	if err != nil {
		w.WriteHeader(http.StatusInternalServerError)
		return
	}

	imageID := uuid.NewUUID().String()
	err = UploadToS3(buf, imageID)
	if err != nil {
		w.WriteHeader(http.StatusInternalServerError)
		return
	}

	fmt.Fprintf(w, "Image uploaded successfully: %s", imageID)
}

// GetImage retrieves the resized image from S3 by its unique identifier
func GetImage(w http.ResponseWriter, r *http.Request) {
	vars := mux.Vars(r)
	imageID := vars["id"]

	sess, _ := session.NewSession(&aws.Config{
		Region: aws.String("your-aws-region"),
	})

	svc := s3.New(sess)

	req, _ := svc.GetObjectRequest(&s3.GetObjectInput{
		Bucket: aws.String(S3_BUCKET),
		Key:    aws.String(imageID),
	})
	urlStr, err := req.Presign(15 * 60)
	if err != nil {
		w.WriteHeader(http.StatusInternalServerError)
		return
	}

	http.Redirect(w, r, urlStr, http.StatusTemporaryRedirect)
}

// UploadToS3 uploads the resized image to Amazon S3
func UploadToS3(file *bytes.Buffer, key string) error {
	sess, _ := session.NewSession(&aws.Config{
		Region: aws.String("your-aws-region"),
	})

	svc := s3.New(sess)

	_, err := svc.PutObject(&s3.PutObjectInput{
		Bucket:               aws.String(S3_BUCKET),
		Key:                  aws.String(key),
		ACL:                  aws.String("private"),
		Body:                 bytes.NewReader(file.Bytes()),
		ContentLength:        aws.Int64(int64(file.Len())),
		ContentType:          aws.String(http.DetectContentType(file.Bytes())),
		ContentDisposition:   aws.String("attachment"),
		ServerSideEncryption: aws.String("AES256"),
	})

	return err
}

