	return nil
}

func getUserByID(db *sql.DB, id int) (*User, error) {
	sqlStatement := `SELECT id, name, email, age FROM users WHERE id=$1;`
	var user User
	row := db.QueryRow(sqlStatement, id)
	err := row.Scan(&user.ID, &user.Name, &user.Email, &user.Age)

	switch err {
	case sql.ErrNoRows:
