package main

import (
	"bufio"
	"fmt"
	"net"
	"os"
	"strings"
)

// Storage for key-value pairs
var storage = make(map[string]string)

// Handle incoming connections and process commands
func handleConnection(conn net.Conn) {
	defer conn.Close()

	reader := bufio.NewReader(conn)
	for {
		command, err := reader.ReadString('\n')
		if err != nil {
			fmt.Println("Error reading command:", err)
			return
		}

		command = strings.TrimSpace(command)
		parts := strings.SplitN(command, " ", 3)

		switch parts[0] {
		case "SET":
			if len(parts) < 3 {
				conn.Write([]byte("ERR: SET requires a key and value\n"))
			} else {
				storage[parts[1]] = parts[2]
				conn.Write([]byte("OK\n"))
			}
		case "GET":
			if len(parts) < 2 {
				conn.Write([]byte("ERR: GET requires a key\n"))
			} else {
				value, ok := storage[parts[1]]
				if !ok {
					conn.Write([]byte("ERR: Key not found\n"))
				} else {
					conn.Write([]byte(value + "\n"))
				}
			}
		case "DELETE":
			if len(parts) < 2 {
				conn.Write([]byte("ERR: DELETE requires a key\n"))
			} else {
				delete(storage, parts[1])
				conn.Write([]byte("OK\n"))
			}
		default:
			conn.Write([]byte("ERR: Unknown command\n"))
		}
	}
}

func main() {
	port := "8080"

	listener, err := net.Listen("tcp", ":"+port)
	if err != nil {
		fmt.Println("Error starting server:", err)
		os.Exit(1)
	}
	defer listener.Close()

	fmt.Println("Server listening on port", port)

	for {
		conn, err := listener.Accept()
		if err != nil {
			fmt.Println("Error accepting connection:", err)
			continue
		}

		go handleConnection(conn)
	}
}

