import (
	"flag"
	"fmt"
	"github.com/fsnotify/fsnotify"
	"log"
	"os"
	"time"
)

func main() {
	dirPtr := flag.String("dir", ".", "The target directory to monitor")
	logFilePtr := flag.String("log", "monitor.log", "The output log file path")

	flag.Parse()

	watcher, err := fsnotify.NewWatcher()
	if err != nil {
		log.Fatal(err)
	}
	defer watcher.Close()

	done := make(chan bool)
	go func() {
		for {
			select {
			case event, ok := <-watcher.Events:
				if !ok {
					return
				}

				timestamp := time.Now().Format(time.RFC3339)
				eventStr := fmt.Sprintf("%s: %s\n", timestamp, event)
				fmt.Print(eventStr)

				f, err := os.OpenFile(*logFilePtr, os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0644)
				if err != nil {
					log.Println("Error opening log file:", err)
				} else {
					if _, err := f.WriteString(eventStr); err != nil {
						log.Println("Error writing to log file:", err)
					}
					f.Close()
				}

			case err, ok := <-watcher.Errors:
				if !ok {
					return
				}
				log.Println("Error:", err)
			}
		}
	}()

	err = watcher.Add(*dirPtr)
	if err != nil {
		log.Fatal(err)
	}
	<-done
}

Here's a Golang program that implements the Sieve of Eratosthenes algorithm for finding prime numbers up to a given limit:

```go
package main

import (
	"fmt"
	"os"
	"strconv"
)

func sieveOfEratosthenes(limit int) []int {
	isPrime := make([]bool, limit+1)
	for i := 2; i <= limit; i++ {
		isPrime[i] = true
	}

	for p := 2; p*p <= limit; p++ {
		if isPrime[p] {
			for i := p * p; i <= limit; i += p {
				isPrime[i] = false
			}
		}
	}

	primes := []int{}
	for i := 2; i <= limit; i++ {
		if isPrime[i] {
			primes = append(primes, i)
		}
	}

	return primes
}

func main() {
	if len(os.Args) != 2 {
		fmt.Println("Usage: go run sieve.go <limit>")
		os.Exit(1)
	}

	limit, err := strconv.Atoi(os.Args[1])
	if err != nil || limit < 2 {
		fmt.Println("Please provide a valid integer greater than or equal to 2")
		os.Exit(1)
	}

	primeNumbers := sieveOfEratosthenes(limit)
	fmt.Printf("Prime numbers less than or equal to %d:\n", limit)
	for _, prime := range primeNumbers {
		fmt.Printf("%d ", prime)
	}
	fmt.Println()
}
```

To run this program, save it in a file named `sieve.go` and then execute the following command:

```sh
$ go run sieve.go <limit>
```

Replace `<limit>` with the desired upper bound for prime numbers. The program will output all prime numbers less than or equal to the input.

