const (
	host     = "localhost"
	port     = 5432
	user     = "postgres"
	password = "your_password"
	dbname   = "twitter_db"
)

type Tweet struct {
	Text      string `json:"text"`
	Timestamp string `json:"created_at"`
	User      string `json:"user.screen_name"`
}

func connectToTwitter() *anaconda.TwitterApi {
	consumerKey := "your_consumer_key"
	consumerSecret := "your_consumer_secret"
	accessToken := "your_access_token"
	accessSecret := "your_access_secret"

	anaconda.SetConsumerKey(consumerKey)
	anaconda.SetConsumerSecret(consumerSecret)
	api := anaconda.NewTwitterApi(accessToken, accessSecret)

	return api
}

func connectToDatabase() *sql.DB {
	psqlInfo := fmt.Sprintf("host=%s port=%d user=%s password=%s dbname=%s sslmode=disable",
		host, port, user, password, dbname)

	db, err := sql.Open("postgres", psqlInfo)
	if err != nil {
		log.Fatal(err)
	}

	err = db.Ping()
	if err != nil {
		log.Fatal(err)
	}

	return db
}

func storeTweet(db *sql.DB, tweet Tweet) error {
	query := `INSERT INTO tweets (text, timestamp, user) VALUES ($1, $2, $3)`
	_, err := db.Exec(query, tweet.Text, tweet.Timestamp, tweet.User)

	if err != nil {
		return err
	}
	return nil
}

func main() {
	api := connectToTwitter()
	db := connectToDatabase()

	defer db.Close()

	v := url.Values{}
	v.Set("track", "your_keyword")
	stream := api.PublicStreamFilter(v)

	for t := range stream.C {
		switch v := t.(type) {
		case anaconda.Tweet:
			var tweet Tweet
			err := json.Unmarshal([]byte(v.Raw), &tweet)
			if err != nil {
				log.Println("Error unmarshalling tweet:", err)
				continue
			}

			err = storeTweet(db, tweet)
			if err != nil {
				log.Println("Error storing tweet:", err)
				continue
			}

			fmt.Printf("Stored tweet: %s\n", tweet.Text)
		default:
			log.Printf("Unknown type in stream: %T\n", v)
		}
	}
}

