package main

import (
	"encoding/csv"
	"fmt"
	"io"
	"log"
	"os"
	"strings"

	"github.com/olivere/elastic"
	"github.com/spf13/cobra"
)

func main() {
	var host, port, index, file, delimiter, quote string
	var columnMappings []string

	var rootCmd = &cobra.Command{
		Use:   "csv-to-es",
		Short: "Import CSV data into Elasticsearch",
		Run: func(cmd *cobra.Command, args []string) {
			esURL := fmt.Sprintf("http://%s:%s", host, port)
			err := importCSV(esURL, index, file, delimiter, quote, columnMappings)
			if err != nil {
				log.Fatal(err)
			}
		},
	}

	rootCmd.Flags().StringVarP(&host, "host", "H", "localhost", "Elasticsearch host")
	rootCmd.Flags().StringVarP(&port, "port", "p", "9200", "Elasticsearch port")
	rootCmd.Flags().StringVarP(&index, "index", "i", "", "Index name (required)")
	rootCmd.MarkFlagRequired("index")
	rootCmd.Flags().StringVarP(&file, "file", "f", "", "Path to the CSV file (required)")
	rootCmd.MarkFlagRequired("file")
	rootCmd.Flags().StringVarP(&delimiter, "delimiter", "d", ",", "Delimiter character")
	rootCmd.Flags().StringVarP(&quote, "quote", "q", "\"", "Quote character")
	rootCmd.Flags().StringSliceVarP(&columnMappings, "columns", "c", nil, "Column mappings (comma-separated)")

	if err := rootCmd.Execute(); err != nil {
		log.Fatal(err)
	}
}

func importCSV(esURL, index, file, delimiter, quote string, columnMappings []string) error {
	client, err := elastic.NewClient(elastic.SetURL(esURL))
	if err != nil {
		return fmt.Errorf("failed to create Elasticsearch client: %v", err)
	}

	f, err := os.Open(file)
	if err != nil {
		return fmt.Errorf("failed to open CSV file: %v", err)
	}
	defer f.Close()

	r := csv.NewReader(f)
	r.Comma = rune(delimiter[0])
	r.LazyQuotes = true

	bulkRequest := client.Bulk()
	for {
		record, err := r.Read()
		if err == io.EOF {
			break
		}
		if err != nil {
			return fmt.Errorf("error reading CSV record: %v", err)
		}

		doc := make(map[string]interface{})
		for i, value := range record {
			columnName := fmt.Sprintf("column%d", i+1)
			if len(columnMappings) > i && columnMappings[i] != "" {
				columnName = columnMappings[i]
			}
			doc[columnName] = value
		}

		req := elastic.NewBulkIndexRequest().Index(index).Doc(doc)
		bulkRequest.Add(req)
	}

	_, err = bulkRequest.Do(context.Background())
	if err != nil {
		return fmt.Errorf("failed to execute bulk request: %v", err)
	}

	return nil
}

Here's a Golang program that connects to a MariaDB database, creates a table called "products", and performs CRUD operations on the table through user input:

```go
package main

import (
	"database/sql"
	"fmt"
	"log"
	"os"

	_ "github.com/go-sql-driver/mysql"
)

type Product struct {
	ID       int
	Name     string
	Price    float64
	Quantity int
}

func main() {
	db, err := sql.Open("mysql", "username:password@tcp(localhost:3306)/dbname")
	if err != nil {
		log.Fatal(err)
	}
	defer db.Close()

	err = createTable(db)
	if err != nil {
		log.Fatal(err)
	}

	for {
		fmt.Println("\nChoose an operation:")
		fmt.Println("1. Create product")
		fmt.Println("2. Read products")
		fmt.Println("3. Update product")
		fmt.Println("4. Delete product")
		fmt.Println("5. Exit")

		var choice int
		fmt.Scan(&choice)

		switch choice {
		case 1:
			err = createProduct(db)
		case 2:
			err = readProducts(db)
		case 3:
			err = updateProduct(db)
		case 4:
			err = deleteProduct(db)
		case 5:
			os.Exit(0)
		default:
			fmt.Println("Invalid choice.")
			continue
		}

		if err != nil {
			log.Fatal(err)
		}
	}
}

func createTable(db *sql.DB) error {
	query := `CREATE TABLE IF NOT EXISTS products (
		id INT AUTO_INCREMENT,
		name VARCHAR(255) NOT NULL,
		price DECIMAL(10, 2) NOT NULL,
		quantity INT NOT NULL,
		PRIMARY KEY (id)
	);`

	_, err := db.Exec(query)
	return err
}

func createProduct(db *sql.DB) error {
	var p Product

	fmt.Print("Enter product name: ")
	fmt.Scan(&p.Name)

	fmt.Print("Enter product price: ")
	fmt.Scan(&p.Price)

	fmt.Print("Enter product quantity: ")
	fmt.Scan(&p.Quantity)

	query := "INSERT INTO products (name, price, quantity) VALUES (?, ?, ?)"
	_, err := db.Exec(query, p.Name, p.Price, p.Quantity)

	if err == nil {
		fmt.Println("Product created successfully.")
	}
	return err
}

func readProducts(db *sql.DB) error {
	rows, err := db.Query("SELECT id, name, price, quantity FROM products")
	if err != nil {
		return err
	}
	defer rows.Close()

	fmt.Printf("\n%-5s %-20s %-10s %s\n", "ID", "Name", "Price", "Quantity")

	for rows.Next() {
		var p Product
		err = rows.Scan(&p.ID, &p.Name, &p.Price, &p.Quantity)
		if err != nil {
			return err
		}
		fmt.Printf("%-5d %-20s %-10.2f %d\n", p.ID, p.Name, p.Price, p.Quantity)
	}

	return rows.Err()
}

func updateProduct(db *sql.DB) error {
	var p Product

	fmt.Print("Enter product ID to update: ")
	fmt.Scan(&p.ID)

	fmt.Print("Enter new product name: ")
	fmt.Scan(&p.Name)

	fmt.Print("Enter new product price: ")
	fmt.Scan(&p.Price)

	fmt.Print("Enter new product quantity: ")
	fmt.Scan(&p.Quantity)

	query := "UPDATE products SET name=?, price=?, quantity=? WHERE id=?"
	result, err := db.Exec(query, p.Name, p.Price, p.Quantity, p.ID)

	if err == nil {
		rowsAffected, _ := result.RowsAffected()
		if rowsAffected == 0 {
			fmt.Println("No product found with the given ID.")
		} else {
			fmt.Println("Product updated successfully.")
		}
	}
	return err
}

func deleteProduct(db *sql.DB) error {
	var id int

	fmt.Print("Enter product ID to delete: ")
	fmt.Scan(&id)

	query := "DELETE FROM products WHERE id=?"
	result, err := db.Exec(query, id)

	if err == nil {
		rowsAffected, _ := result.RowsAffected()
		if rowsAffected == 0 {
			fmt.Println("No product found with the given ID.")
		} else {
			fmt.Println("Product deleted successfully.")
		}
	}
	return err
}
```

