import (
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"strconv"

	"github.com/gorilla/mux"
)

// Book struct to store book information
type Book struct {
	Title          string `json:"title"`
	Author         string `json:"author"`
	PublicationYear int    `json:"publication_year"`
	ISBN           string `json:"isbn"`
}

var books []Book

// getBooks returns all books in the collection
func getBooks(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(books)
}

// addBook adds a new book to the collection
func addBook(w http.ResponseWriter, r *http.Request) {
	var newBook Book
	json.NewDecoder(r.Body).Decode(&newBook)

	books = append(books, newBook)
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(newBook)
}

// updateBook updates an existing book by ISBN
func updateBook(w http.ResponseWriter, r *http.Request) {
	params := mux.Vars(r)
	isbn := params["isbn"]

	for index, book := range books {
		if book.ISBN == isbn {
			books = append(books[:index], books[index+1:]...)
			var updatedBook Book
			json.NewDecoder(r.Body).Decode(&updatedBook)
			updatedBook.ISBN = isbn
			books = append(books, updatedBook)
			w.Header().Set("Content-Type", "application/json")
			json.NewEncoder(w).Encode(updatedBook)
			return
		}
	}
	http.Error(w, "Book not found", http.StatusNotFound)
}

// deleteBook deletes a book by ISBN from the collection
func deleteBook(w http.ResponseWriter, r *http.Request) {
	params := mux.Vars(r)
	isbn := params["isbn"]

	for index, book := range books {
		if book.ISBN == isbn {
			books = append(books[:index], books[index+1:]...)
			w.WriteHeader(http.StatusNoContent)
			return
		}
	}
	http.Error(w, "Book not found", http.StatusNotFound)
}

func main() {
	router := mux.NewRouter()

	// Sample data
	books = append(books,
		Book{Title: "The Catcher in the Rye", Author: "J.D. Salinger", PublicationYear: 1951, ISBN: "9780316769488"},
		Book{Title: "To Kill a Mockingbird", Author: "Harper Lee", PublicationYear: 1960, ISBN: "9780060935467"},
	)

	// API endpoints
	router.HandleFunc("/api/books", getBooks).Methods("GET")
	router.HandleFunc("/api/books", addBook).Methods("POST")
	router.HandleFunc("/api/books/{isbn}", updateBook).Methods("PUT")
	router.HandleFunc("/api/books/{isbn}", deleteBook).Methods("DELETE")

	port := 8080
	fmt.Printf("Starting server on port %d\n", port)
	log.Fatal(http.ListenAndServe(":"+strconv.Itoa(port), router))
}

