		Title:          "The Catcher in the Rye",
		Author:         "J.D. Salinger",
		PublicationDate: time.Date(1951, 7, 16, 0, 0, 0, 0, time.UTC),
		ISBN:           "9780316769488",
	}

	id, err := insertBook(db, book)
	if err != nil {
		log.Fatal(err)
	}
	fmt.Printf("Inserted book with ID %d\n", id)

	book.ID = id
	book.Title = "Updated Title"
	err = updateBook(db, book)
	if err != nil {
		log.Fatal(err)
	}
	fmt.Println("Updated book")

	foundBook, err := getBookByID(db, id)
	if err != nil {
		log.Fatal(err)
	}
	fmt.Printf("Found book: %+v\n", foundBook)

	err = deleteBook(db, id)
	if err != nil {
		log.Fatal(err)
	}
	fmt.Println("Deleted book")
}

func createTable(db *sql.DB) error {
	query := `CREATE TABLE IF NOT EXISTS books (
		id INT AUTO_INCREMENT,
		title VARCHAR(255) NOT NULL,
		author VARCHAR(255) NOT NULL,
		publication_date DATE NOT NULL,
		isbn VARCHAR(13) UNIQUE NOT NULL,
		PRIMARY KEY (id)
	)`
	_, err := db.Exec(query)
	return err
}

func insertBook(db *sql.DB, book Book) (int, error) {
	query := "INSERT INTO books(title, author, publication_date, isbn) VALUES (?, ?, ?, ?)"
	result, err := db.Exec(query, book.Title, book.Author, book.PublicationDate, book.ISBN)
	if err != nil {
		return 0, err
	}
	id, err := result.LastInsertId()
	return int(id), err
}

func updateBook(db *sql.DB, book Book) error {
	query := "UPDATE books SET title=?, author=?, publication_date=?, isbn=? WHERE id=?"
	_, err := db.Exec(query, book.Title, book.Author, book.PublicationDate, book.ISBN, book.ID)
	return err
}

func getBookByID(db *sql.DB, id int) (*Book, error) {
	query := "SELECT id, title, author, publication_date, isbn FROM books WHERE id=?"
	row := db.QueryRow(query, id)

	var book Book
	err := row.Scan(&book.ID, &book.Title, &book.Author, &book.PublicationDate, &book.ISBN)
	if err == sql.ErrNoRows {
		return nil, fmt.Errorf("book not found")
	} else if err != nil {
		return nil, err
	}
	return &book, nil
}

func deleteBook(db *sql.DB, id int) error {
	query := "DELETE FROM books WHERE id=?"
	_, err := db.Exec(query, id)
	return err
}

#include <iostream>
#include <string>
#include <sqlite3.h>

// Callback function for query results
static int callback(void *data, int argc, char **argv, char **azColName) {
    for (int i = 0; i < argc; i++) {
        std::cout << azColName[i] << " = " << (argv[i] ? argv[i] : "NULL") << "\n";
    }
    std::cout << std::endl;
    return 0;
}

// Function to execute SQL statements
void execute_sql(sqlite3 *db, const std::string &sql) {
    char *zErrMsg = nullptr;
    int rc = sqlite3_exec(db, sql.c_str(), callback, nullptr, &zErrMsg);

    if (rc != SQLITE_OK) {
        std::cerr << "SQL error: " << zErrMsg << std::endl;
        sqlite3_free(zErrMsg);
    } else {
        std::cout << "SQL executed successfully" << std::endl;
    }
}

int main(int argc, char* argv[]) {
    if (argc < 2) {
        std::cerr << "Usage: " << argv[0] << " DATABASE [SQL_STATEMENT]" << std::endl;
        return 1;
    }

    sqlite3 *db;
    int rc = sqlite3_open(argv[1], &db);

    if (rc) {
        std::cerr << "Can't open database: " << sqlite3_errmsg(db) << std::endl;
        return rc;
    } else {
        std::cout << "Opened database successfully" << std::endl;
    }

    if (argc > 2) {
        execute_sql(db, argv[2]);
    }

    sqlite3_close(db);
    return 0;
}

