func main() {
	url := "https://raw.githubusercontent.com/dwyl/english-words/master/words.txt"

	resp, err := http.Get(url)
	if err != nil {
		fmt.Println("Error fetching URL:", err)
		return
	}
	defer resp.Body.Close()

	body, err := ioutil.ReadAll(resp.Body)
	if err != nil {
		fmt.Println("Error reading response body:", err)
		return
	}

	text := string(body)
	wordFrequencies := countWords(text)

	topWords := getTopNWords(wordFrequencies, 10)

	for i, word := range topWords {
		fmt.Printf("%d. %s: %d\n", i+1, word.word, word.frequency)
	}
}

type WordFrequency struct {
	word      string
	frequency int
}

func countWords(text string) map[string]int {
	frequencies := make(map[string]int)
	scanner := bufio.NewScanner(strings.NewReader(text))
	scanner.Split(bufio.ScanWords)

	for scanner.Scan() {
		word := strings.ToLower(scanner.Text())
		frequencies[word]++
	}

	return frequencies
}

func getTopNWords(frequencies map[string]int, n int) []WordFrequency {
	wordList := make([]WordFrequency, 0, len(frequencies))

	for word, freq := range frequencies {
		wordList = append(wordList, WordFrequency{word, freq})
	}

	sort.Slice(wordList, func(i, j int) bool {
		return wordList[i].frequency > wordList[j].frequency
	})

	return wordList[:n]
}

Here's a simple Golang program that generates Mandelbrot and Julia fractal images based on user input for the type of fractal, size, and color scheme. The generated image is saved as a PNG file.

```go
package main

import (
	"fmt"
	"image"
	"image/color"
	"image/png"
	"math/cmplx"
	"os"
	"strconv"
)

type FractalType int

const (
	Mandelbrot FractalType = iota
	Julia
)

func main() {
	var fractalType FractalType
	var width, height int
	var colorScheme string

	fmt.Print("Enter fractal type (Mandelbrot or Julia): ")
	var fractalInput string
	fmt.Scanln(&fractalInput)
	switch fractalInput {
	case "Mandelbrot":
		fractalType = Mandelbrot
	case "Julia":
		fractalType = Julia
	default:
		fmt.Println("Invalid fractal type")
		return
	}

	fmt.Print("Enter width: ")
	fmt.Scanln(&width)
	fmt.Print("Enter height: ")
	fmt.Scanln(&height)

	fmt.Print("Enter color scheme (red, green, blue): ")
	fmt.Scanln(&colorScheme)

	img := generateFractal(fractalType, width, height, colorScheme)
	saveImage(img, fmt.Sprintf("%s_fractal_%dx%d.png", fractalInput, width, height))
}

func generateFractal(fractalType FractalType, width, height int, colorScheme string) *image.RGBA {
	img := image.NewRGBA(image.Rect(0, 0, width, height))

	for y := 0; y < height; y++ {
		for x := 0; x < width; x++ {
			c := complex(float64(x)/float64(width)*3.5-2.5, float64(y)/float64(height)*2-1)
			var z complex128
			if fractalType == Julia {
				z = c
				c = -0.8 + 0.156i
			}
			color := getColor(iterate(c, z), colorScheme)
			img.Set(x, y, color)
		}
	}

	return img
}

func iterate(c, z complex128) int {
	const maxIter = 1000

	for i := 0; i < maxIter; i++ {
		z = z*z + c
		if cmplx.Abs(z) > 2 {
			return i
		}
	}

	return maxIter
}

func getColor(iter int, colorScheme string) color.RGBA {
	var r, g, b uint8
	switch colorScheme {
	case "red":
		r = uint8(255 * iter / 1000)
	case "green":
		g = uint8(255 * iter / 1000)
	case "blue":
		b = uint8(255 * iter / 1000)
	default:
		r, g, b = uint8(255*iter/1000), uint8(255*iter/1000), uint8(255*iter/1000)
	}
	return color.RGBA{r, g, b, 255}
}

func saveImage(img *image.RGBA, filename string) {
	file, err := os.Create(filename)
	if err != nil {
		fmt.Println("Error creating file:", err)
		return
	}
	defer file.Close()

	err = png.Encode(file, img)
	if err != nil {
		fmt.Println("Error encoding image:", err)
	}
}
```

