	router.HandleFunc("/products/{id}", updateProduct).Methods("PUT")
	router.HandleFunc("/products/{id}", deleteProduct).Methods("DELETE")
	router.HandleFunc("/products", listProducts).Methods("GET")

	http.ListenAndServe(":8080", router)
}

func initElasticSearch() error {
	ctx := context.Background()

	exists, err := client.IndexExists(elasticIndexName).Do(ctx)
	if err != nil {
		return err
	}
	if !exists {
		createIndex, err := client.CreateIndex(elasticIndexName).Do(ctx)
		if err != nil {
			return err
		}
		if !createIndex.Acknowledged {
			return fmt.Errorf("index creation not acknowledged")
		}
	}

	return nil
}

func createProduct(w http.ResponseWriter, r *http.Request) {
	var product Product

	err := json.NewDecoder(r.Body).Decode(&product)
	if err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}

	ctx := context.Background()
	result, err := client.Index().
		Index(elasticIndexName).
		Type(elasticTypeName).
		BodyJson(product).
		Refresh("wait_for").
		Do(ctx)

	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}

	product.ID = result.Id
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(product)
}

func getProduct(w http.ResponseWriter, r *http.Request) {
	params := mux.Vars(r)
	id := params["id"]

	ctx := context.Background()
	result, err := client.Get().
		Index(elasticIndexName).
		Type(elasticTypeName).
		Id(id).
		Do(ctx)

	if err != nil {
		http.Error(w, err.Error(), http.StatusNotFound)
		return
	}

	var product Product
	err = json.Unmarshal(result.Source, &product)
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}

	product.ID = result.Id
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(product)
}

func updateProduct(w http.ResponseWriter, r *http.Request) {
	params := mux.Vars(r)
	id := params["id"]

	var product Product
	err := json.NewDecoder(r.Body).Decode(&product)
	if err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}

	ctx := context.Background()
	_, err = client.Update().
		Index(elasticIndexName).
		Type(elasticTypeName).
		Id(id).
		Doc(product).
		Refresh("wait_for").
		Do(ctx)

	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}

	product.ID = id
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(product)
}

func deleteProduct(w http.ResponseWriter, r *http.Request) {
	params := mux.Vars(r)
	id := params["id"]

	ctx := context.Background()
	_, err := client.Delete().
		Index(elasticIndexName).
		Type(elasticTypeName).
		Id(id).
		Refresh("wait_for").
		Do(ctx)

	if err != nil {
		http.Error(w, err.Error(), http.StatusNotFound)
		return
	}

	w.WriteHeader(http.StatusOK)
}

func listProducts(w http.ResponseWriter, r *http.Request) {
	query := elastic.NewMatchAllQuery()

	ctx := context.Background()
	results, err := client.Search().
		Index(elasticIndexName).
		Query(query).
		From(0).Size(100).
		Pretty(true).
		Do(ctx)

	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}

	var products []Product

	for _, hit := range results.Hits.Hits {
		var product Product
		err := json.Unmarshal(hit.Source, &product)
		if err != nil {
			http.Error(w, err.Error(), http.StatusInternalServerError)
			return
		}
		product.ID = hit.Id
		products = append(products, product)
	}

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(products)
}

