```go
package main

import (
	"fmt"
	"strings"
)

func main() {
	var input string
	fmt.Println("Enter a string:")
	fmt.Scanln(&input)
	input = strings.ToLower(input)

	if isPalindrome(input) {
		fmt.Println("Palindrome")
