```go
package main

import (
	"bufio"
	"fmt"
	"os"
	"strings"

	"github.com/bradfitz/gomemcache/memcache"
)

func main() {
	// Connect to the Memcached server.
	mc := memcache.New("localhost:11211")

	reader := bufio.NewReader(os.Stdin)
	fmt.Println("Memcached CLI")
	fmt.Println("---------------------")

	for {
		fmt.Print("-> ")
		input, _ := reader.ReadString('\n')
		command := strings.Split(strings.TrimSpace(input), " ")

		switch command[0] {
		case "set":
			if len(command) < 3 {
				fmt.Println("Usage: set <key> <value>")
				continue
			}
			err := mc.Set(&memcache.Item{Key: command[1], Value: []byte(command[2])})
			if err != nil {
				fmt.Printf("Error setting value: %v\n", err)
			} else {
				fmt.Println("Value set successfully.")
			}

		case "get":
			if len(command) < 2 {
				fmt.Println("Usage: get <key>")
				continue
			}
			item, err := mc.Get(command[1])
			if err != nil {
				fmt.Printf("Error getting value: %v\n", err)
			} else {
				fmt.Printf("Value: %s\n", string(item.Value))
			}

		case "delete":
			if len(command) < 2 {
				fmt.Println("Usage: delete <key>")
				continue
			}
			err := mc.Delete(command[1])
			if err != nil {
				fmt.Printf("Error deleting value: %v\n", err)
			} else {
				fmt.Println("Value deleted successfully.")
			}

		case "quit":
			fmt.Println("Bye!")
			os.Exit(0)

		default:
			fmt.Println("Invalid command. Available commands: set, get, delete, quit")
		}
	}
}
```

3. Make sure you have a Memcached server running on `localhost` and listening to port `11211`. If not, install and start the Memcached server.

4. Run your application by executing this command in your terminal:

```bash
go run main.go
```

5. You should now see a simple CLI for interacting with the Memcached server. Use the following commands to interact with the cache:

- To set a key-value pair: `set <key> <value>`
- To get the value of a key: `get <key>`
- To delete a key-value pair: `delete <key>`
- To exit the CLI: `quit`

